-- ----------------------------
-- Table structure for agent_cmd
-- ----------------------------
DROP TABLE IF EXISTS `agent_cmd`;
CREATE TABLE `agent_cmd`  (
  `id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'id',
  `cmd_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '指令编号',
  `cmd_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '指令名称',
  `cmd_param` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '指令参数',
  `send_time` datetime NOT NULL COMMENT '指令发送时间',
  `cmd_status` tinyint NOT NULL COMMENT '指令状态 0 执行中 1 已撤回 2 执行完成',
  `cost_time` bigint UNSIGNED NULL DEFAULT NULL COMMENT '指令执行耗时 单位:秒',
  `agent_num` int UNSIGNED NULL DEFAULT NULL COMMENT 'Agent总数',
  `received_num` int UNSIGNED NULL DEFAULT NULL COMMENT '已接收指令Agent数量',
  `executed_num` int UNSIGNED NULL DEFAULT NULL COMMENT '已执行指令Agent数量',
  `successful_num` int UNSIGNED NULL DEFAULT NULL COMMENT '执行失败Agent数量',
  `failed_num` int UNSIGNED NULL DEFAULT NULL COMMENT '执行成功Agent数量',
  `tenant_id` int UNSIGNED NULL DEFAULT NULL COMMENT '租户id',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `update_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idex_cmd_no`(`cmd_no` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'Agent指令' ROW_FORMAT = DYNAMIC;

