  `scan_engine` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '扫描引擎 LOCAL:本地引擎 HUNTER:鹰图 QUAKE:Quake',
