  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `FK_Reference_5`(`scan_task_id` ASC) USING BTREE,
  CONSTRAINT `FK_Reference_5` FOREIGN KEY (`scan_task_id`) REFERENCES `amtool_scan_task` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '引擎调用记录' ROW_FORMAT = DYNAMIC;

