-- ----------------------------
-- Table structure for amtool_scan_task
-- ----------------------------
DROP TABLE IF EXISTS `amtool_scan_task`;
CREATE TABLE `amtool_scan_task`  (
  `id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '主键ID',
  `task_name` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '任务名称',
  `task_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '任务类型 HOST_SCAN: 主机扫描任务 WEB_SCAN:网站扫描任务 MIXED:混合扫描任务 WEB_SEARCH:互联网搜索任务',
  `scan_target` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '扫描目标',
  `scan_port` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '扫描端口 COMMON:常规端口 FULL:全端口 自定义格式：1,10-100,3306',
  `scan_engine` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '扫描引擎 LOCAL:本地引擎 HUNTER:鹰图 QUAKE:Quake YIAN:YIAN',
  `scan_item` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '扫描内容 PORT:端口存活 FINGERPRINT:指纹识别 DIRECTORY:目录扫描 SUBDOMAIN:子域探测 INTERNET_SEARCH:互联网资产搜索',
  `scan_speed` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '扫描速度 FAST:快 NORMAL:正常 SLOW:慢',
  `scan_type` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '扫描方式  FULLY_CONNECTED:全连接 STATELESS：无状态',
  `extend_param` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '扩展参数，格式[{\"value\":\"directoryDepth\",\"code\":\"2\"}]',
  `begin_time` datetime NULL DEFAULT NULL COMMENT '扫描开始时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '扫描结束时间',
  `scan_progress` int NULL DEFAULT NULL COMMENT '扫描进度',
  `task_status` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '任务状态，参考字典key=amtoolTaskStatus',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `discover_asset_num` int NULL DEFAULT NULL COMMENT '发现资产数',
  `retry_num` int NULL DEFAULT 0 COMMENT '重试次数',
  `deleted` tinyint(1) NOT NULL COMMENT '删除标记 0表示未删除 1表示已删除',
  `creator` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updater` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  `customer_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '客户id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '资产测绘任务' ROW_FORMAT = DYNAMIC;

