-- ----------------------------
-- Table structure for check_record
-- ----------------------------
DROP TABLE IF EXISTS `check_record`;
CREATE TABLE `check_record`  (
  `id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'id',
  `check_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '巡检编号',
  `strategy_id` varchar(19) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '策略id',
  `checkitem_num` int UNSIGNED NULL DEFAULT NULL COMMENT '检查项数量',
  `host_num` int UNSIGNED NULL DEFAULT NULL COMMENT '主机数',
  `win_num` int NULL DEFAULT NULL COMMENT 'windows主机数',
  `linux_num` int NULL DEFAULT NULL COMMENT 'linux主机数',
  `unix_num` int NULL DEFAULT NULL COMMENT 'unix主机数',
  `failed_num` int UNSIGNED NULL DEFAULT NULL COMMENT '执行失败数',
  `successful_num` int UNSIGNED NULL DEFAULT NULL COMMENT '执行成功数',
