  `pass_num` int UNSIGNED NULL DEFAULT NULL COMMENT '通过项',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '结束时间',
  `check_status` tinyint NOT NULL COMMENT '巡检状态 0 检查中 1 检查完成 2 检查异常结束',
  `del_flag` tinyint NULL DEFAULT NULL COMMENT '删除状态0 正常 1 已删除',
  `tenant_id` int UNSIGNED NULL DEFAULT NULL COMMENT '租户id',
