  `os_version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作系统版本',
  `architecture` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '架构',
  `check_time` datetime NOT NULL COMMENT '检查时间',
  `checkitem_num` int UNSIGNED NULL DEFAULT NULL COMMENT '检查项数量',
  `risk_num` int UNSIGNED NULL DEFAULT NULL COMMENT '风险项',
  `pass_num` int UNSIGNED NULL DEFAULT NULL COMMENT '通过项',
  `ignore_num` int UNSIGNED NULL DEFAULT NULL COMMENT '忽略项',
  `handle_num` int UNSIGNED NULL DEFAULT NULL COMMENT '处置项',
  `not_handle_num` int UNSIGNED NULL DEFAULT NULL COMMENT '未处置项',
  `not_need_handle` int UNSIGNED NULL DEFAULT NULL COMMENT '无需处置项',
  `conclusion` tinyint NULL DEFAULT NULL COMMENT '巡检结论 参考字典表code=conclusion 0 安全 1 存在安全隐患 2 已被入侵',
  `conclusion_msg` varchar(400) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '巡检结论描述',
  `description` varchar(4000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '巡检说明',
  `handle_description` varchar(4000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '处置情况说明',
  `suggestion` varchar(4000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '加固建议',
  `tenant_id` int UNSIGNED NULL DEFAULT NULL COMMENT '租户id',
  `del_flag` tinyint NULL DEFAULT NULL COMMENT '删除状态0 正常 1 已删除',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `update_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `os_code` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作系统分类代码',
  `check_status` tinyint NULL DEFAULT NULL COMMENT '巡检状态 0 检查中 1 检查完成 2 检查异常结束',
  `data_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '上报数据id',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_record_id`(`record_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '巡检结果' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of check_result
-- ----------------------------

