  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_result_id`(`result_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '巡检结果明细' ROW_FORMAT = DYNAMIC;

