  `app_upload_interval` int UNSIGNED NULL DEFAULT NULL COMMENT '上传数据间隔 单位:秒',
  `agent_heartbeat_interval` int UNSIGNED NULL DEFAULT NULL COMMENT 'Agent心跳上报间隔',
  `agent_upgrade_interval` int UNSIGNED NULL DEFAULT NULL COMMENT 'Agent升级检测间隔',
