  INDEX `idx_app_no`(`app_no` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '应用参数' ROW_FORMAT = DYNAMIC;

