  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  `updater` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '修改人',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `fk_ectool_check_record_template_id`(`template_id` ASC) USING BTREE,
  CONSTRAINT `fk_ectool_check_record_template_id` FOREIGN KEY (`template_id`) REFERENCES `ectool_template` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '设备巡检记录' ROW_FORMAT = DYNAMIC;

