  `template_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '巡检模板ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `fk_ectool_check_result_record_id`(`check_record_id` ASC) USING BTREE,
  CONSTRAINT `fk_ectool_check_result_record_id` FOREIGN KEY (`check_record_id`) REFERENCES `ectool_check_record` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '设备巡检结果' ROW_FORMAT = DYNAMIC;

