  `source_id` bigint NULL DEFAULT NULL COMMENT '执行来源id',
  `description` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '执行描述',
  `exec_seq` int NULL DEFAULT 0 COMMENT '执行序列',
