  `start_time` datetime(3) NULL DEFAULT NULL COMMENT '执行开始时间',
  `finish_time` datetime(3) NULL DEFAULT NULL COMMENT '执行完成时间',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
