  `evaluate_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '评估说明',
  `evaluate_time` datetime NULL DEFAULT NULL COMMENT '评估时间',
  `data_origin` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '数据来源 参考字典key=hrtoolDataOrigin',
  `creator` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updater` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '删除标记 0表示未删除 1表示已删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `FKhrtool_tas445654`(`task_result_id` ASC) USING BTREE,
  INDEX `FKhrtool_tas253431`(`check_item_id` ASC) USING BTREE,
  CONSTRAINT `FKhrtool_tas253431` FOREIGN KEY (`check_item_id`) REFERENCES `hrtool_check_item` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `FKhrtool_tas445654` FOREIGN KEY (`task_result_id`) REFERENCES `hrtool_task_result` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '配置核查任务明细' ROW_FORMAT = DYNAMIC;

