-- ----------------------------
-- Table structure for hrtool_task_result
-- ----------------------------
DROP TABLE IF EXISTS `hrtool_task_result`;
CREATE TABLE `hrtool_task_result`  (
  `id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '检查结果id',
  `task_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '任务id',
  `his_task_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '历史任务id',
  `asset_name` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '资产名称',
  `asset_id` bigint NOT NULL COMMENT '资产id',
  `ip` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '主机ip',
  `os_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作系统名称',
  `check_ok_num` int NULL DEFAULT NULL COMMENT '合规项',
  `check_ng_num` int NULL DEFAULT NULL COMMENT '不合规项',
  `check_status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '检查状态 参考字典key=hrtoolCheckStatus',
  `check_time` datetime NULL DEFAULT NULL COMMENT '检查时间',
  `check_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '检查说明',
  `reinforce_status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '加固状态 参考字典key=hrtoolReinforceStatus',
  `reinforce_time` datetime NULL DEFAULT NULL COMMENT '加固时间',
  `reinforce_description` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '加固说明',
  `reinforce_successful_num` int NULL DEFAULT NULL COMMENT '加固成功数',
  `reinforce_failed_num` int NULL DEFAULT NULL COMMENT '加固失败数',
  `evaluate_ok_num` int NULL DEFAULT NULL COMMENT '评估无风险数',
  `evaluate_ng_num` int NULL DEFAULT NULL COMMENT '评估有风险数',
  `evaluate_time` datetime NULL DEFAULT NULL COMMENT '评估时间',
  `evaluate_status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '评估状态，参考字典key=hrtoolEvaluationStatus',
  `evaluate_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '评估说明',
  `data_origin` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '数据来源 参考字典key=hrtoolDataOrigin',
  `creator` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updater` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '删除标记 0表示未删除 1表示已删除',
  `baseline_ids` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '基线ids',
  `check_item_num` int NULL DEFAULT NULL COMMENT '检查项数量',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `FKhrtool_tas824654`(`task_id` ASC) USING BTREE,
  INDEX `FKhrtool_tas606640`(`his_task_id` ASC) USING BTREE,
  CONSTRAINT `FKhrtool_tas606640` FOREIGN KEY (`his_task_id`) REFERENCES `hrtool_his_task` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `FKhrtool_tas824654` FOREIGN KEY (`task_id`) REFERENCES `hrtool_task` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '配置核查任务执行结果' ROW_FORMAT = DYNAMIC;

