  `deleted` tinyint(1) NOT NULL COMMENT '删除标记 0表示未删除 1表示已删除',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '报告生成任务' ROW_FORMAT = DYNAMIC;

