INSERT INTO `hrtool_baseline` VALUES ('1831602312170614786', 'Linux 操作系统安全基线', 'YIAN', 'os', 'linux', '', 1, '1', '2024-09-05 15:56:35', '1', '2024-09-11 10:20:38', 0, NULL);
INSERT INTO `hrtool_baseline` VALUES ('1832237914704556034', 'Windows操作系统安全基线', 'YIAN', 'os', 'windows', 'secedit /export /cfg %tmp%\\sskit_sec.log\nwmic computersystem get domainrole | find /i /v \"domainrole\" > %tmp%\\sskit_domainrole.txt\necho SCNameSpace = \"\" > %tmp%\\sskit_wmiav.vbs\necho Set objWMIServiceOS = GetObject(\"winmgmts:\\\\.\\root\\CIMV2\") >> %tmp%\\sskit_wmiav.vbs\necho Set colItemsOS = objWMIServiceOS.ExecQuery(\"SELECT * FROM Win32_OperatingSystem\",,48) >> %tmp%\\sskit_wmiav.vbs\necho For Each objItem in colItemsOS >> %tmp%\\sskit_wmiav.vbs\necho     If Left(objItem.Version, 1) ^> \"5\" Then >> %tmp%\\sskit_wmiav.vbs\necho         SCNameSpace = \"winmgmts:\\\\.\\root\\SecurityCenter2\" >> %tmp%\\sskit_wmiav.vbs\necho     Else >> %tmp%\\sskit_wmiav.vbs\necho         SCNameSpace = \"winmgmts:\\\\.\\root\\SecurityCenter\" >> %tmp%\\sskit_wmiav.vbs\necho     End If >> %tmp%\\sskit_wmiav.vbs\necho Exit For >> %tmp%\\sskit_wmiav.vbs\necho Next >> %tmp%\\sskit_wmiav.vbs\necho On Error Resume Next >> %tmp%\\sskit_wmiav.vbs\necho Set objWMIServiceSC = GetObject(SCNameSpace) >> %tmp%\\sskit_wmiav.vbs\necho If Err.Number = 0 Then >> %tmp%\\sskit_wmiav.vbs\necho     Set colItemsSC = objWMIServiceSC.ExecQuery(\"SELECT * FROM AntiVirusProduct\",,48) >> %tmp%\\sskit_wmiav.vbs\necho     For Each objItem in colItemsSC >> %tmp%\\sskit_wmiav.vbs\necho         If Not IsNull(objItem.DisplayName) Then >> %tmp%\\sskit_wmiav.vbs\necho             Wscript.Echo objItem.DisplayName >> %tmp%\\sskit_wmiav.vbs\necho             Wscript.Echo \"nsfocusyes\" >> %tmp%\\sskit_wmiav.vbs\necho         End If >> %tmp%\\sskit_wmiav.vbs\necho     Next >> %tmp%\\sskit_wmiav.vbs\necho End If >> %tmp%\\sskit_wmiav.vbs\necho allKeys = Split(\"安全部队,杀毒,反病毒,防病毒,virus,Spyware,Symantec Endpoint Protection\", \",\") > %tmp%\\sskit_nameav.vbs\necho allSoftNames = \"\" >> %tmp%\\sskit_nameav.vbs\necho const HKEY_LOCAL_MACHINE = ^&H80000002 >> %tmp%\\sskit_nameav.vbs\necho Set objReg = GetObject(\"winmgmts:\\\\.\\root\\default:StdRegProv\") >> %tmp%\\sskit_nameav.vbs\necho arrKeyPath = Array(\"SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Uninstall\", \"SOFTWARE\\Wow6432Node\\Microsoft\\Windows\\CurrentVersion\\Uninstall\") >> %tmp%\\sskit_nameav.vbs\necho For Each strkeyPath In arrKeyPath >> %tmp%\\sskit_nameav.vbs\necho     objReg.EnumKey HKEY_LOCAL_MACHINE, strKeyPath, arrSubKeys >> %tmp%\\sskit_nameav.vbs\necho     If not IsNull(arrSubKeys) Then >> %tmp%\\sskit_nameav.vbs\necho         For Each subkey In arrSubKeys >> %tmp%\\sskit_nameav.vbs\necho             objReg.GetDWORDValue HKEY_LOCAL_MACHINE, strKeyPath + \"\\\" + subkey, \"SystemComponent\", dwValue >> %tmp%\\sskit_nameav.vbs\necho             If IsNull(dwValue) or 0 = dwValue Then >> %tmp%\\sskit_nameav.vbs\necho                 objReg.GetStringValue HKEY_LOCAL_MACHINE, strKeyPath + \"\\\" + subkey, \"DisplayName\", sValue_Name >> %tmp%\\sskit_nameav.vbs\necho                 objReg.GetStringValue HKEY_LOCAL_MACHINE, strKeyPath + \"\\\" + subkey, \"ParentDisplayName\", sValue_PDName >> %tmp%\\sskit_nameav.vbs\necho                 objReg.GetStringValue HKEY_LOCAL_MACHINE, strKeyPath + \"\\\" + subkey, \"ParentKeyName\", sValue_PKName >> %tmp%\\sskit_nameav.vbs\necho                 If not IsNull(sValue_Name) and IsNull(sValue_PDName) and IsNull(sValue_PKName) Then >> %tmp%\\sskit_nameav.vbs\necho                     allSoftNames = allSoftNames + sValue_Name + \",\" >> %tmp%\\sskit_nameav.vbs\necho                 End If >> %tmp%\\sskit_nameav.vbs\necho             End If >> %tmp%\\sskit_nameav.vbs\necho         Next >> %tmp%\\sskit_nameav.vbs\necho     End if >> %tmp%\\sskit_nameav.vbs\necho Next >> %tmp%\\sskit_nameav.vbs\necho For i = 0 To UBound(allKeys) >> %tmp%\\sskit_nameav.vbs\necho     If InStr(allSoftNames, allKeys(i)) Then >> %tmp%\\sskit_nameav.vbs\necho         WScript.Echo \"nsfocusyes\" >> %tmp%\\sskit_nameav.vbs\necho         Exit For >> %tmp%\\sskit_nameav.vbs\necho     End If >> %tmp%\\sskit_nameav.vbs\necho Next >> %tmp%\\sskit_nameav.vbs\necho @echo off > %tmp%\\sskit_processav.bat\n(echo wmic process where \"name = \'kvwsc.exe\' or name = \'kvmonxp.exe\' or name = \'ashserv.exe\' or name = \'aswupdsv.exe\' or name = \'ashdisp.exe\' or name = \'ashwebsv.exe\' or name = \'UpdaterUI.exe\' or name = \'shstat.exe\' or name = \'Tbmon.exe\' or name = \'ccproxy.exe\' or name = \'NTRtscan.exe\'\" get name >> %tmp%\\sskit_processav.bat)\n(echo wmic process where \"name = \'ccSetMgr.exe\' or name = \'defwatch.exe\' or name = \'ISSVC.exe\' or name = \'SPBBCSvc.exe\' or name = \'SNDSrvc.exe\' or name = \'KPFWSvc.exe\' or name = \'KAVStart.exe\' or name = \'KWatch.exe\' or name = \'KMailMon.exe\' or name = \'KPFW32.exe\' or name = \'KPFWSvc.exe\' or name = \'kavscr.exe\' or name = \'avp.exe\' or name = \'kvsrvxp.exe\'\" get name >> %tmp%\\sskit_processav.bat)\n(echo wmic process where \"name = \'Vstskmgr.exe\' or name = \'Mcshield.exe\' or name = \'Frameworkservice.exe\' or name = \'naPrdMgr.exe\' or name = \'mcafee.exe\' or name = \'xcommsvr.exe\' or name = \'bdss.exe\' or name = \'livesrv.exe\' or name = \'bdmcon.exe\' or name = \'bdoesrv.exe\' or name = \'bdnagent.exe\'\" get name >> %tmp%\\sskit_processav.bat)\n(echo wmic process where \"name = \'spidernt.exe\' or name = \'spiderml.exe\' or name = \'drwebscd.exe\' or name = \'spider.exe\' or name = \'nod32kui.exe\' or name = \'nod32krn.exe\' or name = \'MPSVC.exe\' or name = \'MPSVC1.exe\' or name = \'MPSVC2.exe\' or name = \'nod32kui.exe\' or name = \'RavMonD.exe\' or name = \'RfwMain.exe\' or name=\'msseces.exe\'\" get name >> %tmp%\\sskit_processav.bat)\n(echo wmic process where \"name=\'360tray.exe\' or name=\'ZhuDongFangYu.exe\' or name = \'ds_agent\' or name = \'ds_notifier\'\" get name >> %tmp%\\sskit_processav.bat)\necho Set objWMIService = GetObject(\"winmgmts:\\\\.\\root\\CIMV2\") > %tmp%\\sskit_sharecheck.vbs\necho Set colItems = objWMIService.ExecQuery(\"SELECT * FROM Win32_LogicalShareAccess\",,48) >> %tmp%\\sskit_sharecheck.vbs\necho For Each objItem in colItems >> %tmp%\\sskit_sharecheck.vbs\necho     If InStr(objItem.Trustee, \"S-1-1-0\") Then >> %tmp%\\sskit_sharecheck.vbs\necho         Wscript.Echo \"Everyone\" >> %tmp%\\sskit_sharecheck.vbs\necho         Exit For >> %tmp%\\sskit_sharecheck.vbs\necho     End If >> %tmp%\\sskit_sharecheck.vbs\necho Next >> %tmp%\\sskit_sharecheck.vbs\necho On Error Resume Next>%tmp%\\sskit_checkfirewall.vbs\necho set objFirewall = CreateObject(\"HNetCfg.FwMgr\")>>%tmp%\\sskit_checkfirewall.vbs\necho ErrNum = Err.Number>>%tmp%\\sskit_checkfirewall.vbs\necho On Error Goto ^0>>%tmp%\\sskit_checkfirewall.vbs\necho If 0 ^<^> ErrNum Then>>%tmp%\\sskit_checkfirewall.vbs\necho     set ws = CreateObject(\"WScript.Shell\")>>%tmp%\\sskit_checkfirewall.vbs\necho     set FwSvcExec = ws.Exec(\"wmic service where name=\"\"SharedAccess\"\" get state\")>>%tmp%\\sskit_checkfirewall.vbs\necho     FwSvcExec.StdIn.Close>>%tmp%\\sskit_checkfirewall.vbs\necho     FwSvcOut = FwSvcExec.StdOut.ReadAll>>%tmp%\\sskit_checkfirewall.vbs\necho     If InStr(FwSvcOut, \"State\")  Then>>%tmp%\\sskit_checkfirewall.vbs\necho         If InStr(FwSvcOut, \"Running\") Then>>%tmp%\\sskit_checkfirewall.vbs\necho             Wscript.Echo \"Enabled\">>%tmp%\\sskit_checkfirewall.vbs\necho         Else>>%tmp%\\sskit_checkfirewall.vbs\necho             Wscript.Echo \"Disabled\">>%tmp%\\sskit_checkfirewall.vbs\necho         End If>>%tmp%\\sskit_checkfirewall.vbs\necho     Else>>%tmp%\\sskit_checkfirewall.vbs\necho         Wscript.Echo \"NoFirewallWindows\">>%tmp%\\sskit_checkfirewall.vbs\necho     End If>>%tmp%\\sskit_checkfirewall.vbs\necho Else>>%tmp%\\sskit_checkfirewall.vbs\necho     On Error Resume Next>>%tmp%\\sskit_checkfirewall.vbs\necho     set objPolicy = objFirewall.LocalPolicy.CurrentProfile>>%tmp%\\sskit_checkfirewall.vbs\necho     ErrNum = Err.Number>>%tmp%\\sskit_checkfirewall.vbs\necho     On Error Goto ^0>>%tmp%\\sskit_checkfirewall.vbs\necho     If 0 ^<^> ErrNum Then>>%tmp%\\sskit_checkfirewall.vbs\necho         Wscript.Echo \"Enabled\">>%tmp%\\sskit_checkfirewall.vbs\necho     Else>>%tmp%\\sskit_checkfirewall.vbs\necho         If True = objPolicy.FirewallEnabled Then>>%tmp%\\sskit_checkfirewall.vbs\necho             Wscript.Echo \"Enabled\">>%tmp%\\sskit_checkfirewall.vbs\necho         Else>>%tmp%\\sskit_checkfirewall.vbs\necho             Wscript.Echo \"Disabled\">>%tmp%\\sskit_checkfirewall.vbs\necho         End If>>%tmp%\\sskit_checkfirewall.vbs\necho     End If>>%tmp%\\sskit_checkfirewall.vbs\necho End If>>%tmp%\\sskit_checkfirewall.vbs\necho ResultStr = \"\">%tmp%\\sskit_fscheck.vbs\necho Set objWMIService = GetObject(\"winmgmts:\\\\.\\root\\CIMV2\")>>%tmp%\\sskit_fscheck.vbs\necho Set colItems = objWMIService.ExecQuery(\"SELECT * FROM Win32_LogicalDisk\",,48)>>%tmp%\\sskit_fscheck.vbs\necho For Each objItem in colItems>>%tmp%\\sskit_fscheck.vbs\necho     If (3 = objItem.DriveType) and (0 ^<^> Len(objItem.FileSystem)) Then>>%tmp%\\sskit_fscheck.vbs\necho         If 0 = InStr(objItem.FileSystem, \"NTFS\") Then>>%tmp%\\sskit_fscheck.vbs\necho             ResultStr = ResultStr + \",\" + objItem.Name + \"=\" + objItem.FileSystem>>%tmp%\\sskit_fscheck.vbs\necho         End If>>%tmp%\\sskit_fscheck.vbs\necho     End If>>%tmp%\\sskit_fscheck.vbs\necho Next>>%tmp%\\sskit_fscheck.vbs\necho If 0 = Len(ResultStr) Then>>%tmp%\\sskit_fscheck.vbs\necho     Wscript.Echo(\"AllNTFS\")>>%tmp%\\sskit_fscheck.vbs\necho Else>>%tmp%\\sskit_fscheck.vbs\necho     Wscript.Echo(Right(ResultStr, Len(ResultStr) - 1))>>%tmp%\\sskit_fscheck.vbs\necho End If>>%tmp%\\sskit_fscheck.vbs\necho FileName = Wscript.arguments(0)>%tmp%\\sskit_morelines.vbs\necho MoreNumber = CInt(Wscript.arguments(1))>>%tmp%\\sskit_morelines.vbs\necho set objFSO = CreateObject(\"Scripting.FileSystemObject\")>>%tmp%\\sskit_morelines.vbs\necho set objFile = objFSO.OpenTextFile(FileName, 1)>>%tmp%\\sskit_morelines.vbs\necho EchoNumber = ^0>>%tmp%\\sskit_morelines.vbs\necho do while objFile.AtEndOfStream ^<^> True>>%tmp%\\sskit_morelines.vbs\necho     Line = objFile.ReadLine()>>%tmp%\\sskit_morelines.vbs\necho     if Trim(Line) ^<^> \"\" and EchoNumber ^< MoreNumber then>>%tmp%\\sskit_morelines.vbs\necho         EchoNumber = EchoNumber + ^1>>%tmp%\\sskit_morelines.vbs\necho         Wscript.Echo Line>>%tmp%\\sskit_morelines.vbs\necho     end if>>%tmp%\\sskit_morelines.vbs\necho loop>>%tmp%\\sskit_morelines.vbs\necho objFile.Close()>>%tmp%\\sskit_morelines.vbs', 1, '1', '2024-09-07 10:02:15', '1', '2024-09-07 10:02:51', 0, NULL);
