INSERT INTO `hrtool_check_item` VALUES ('1831602312699097089', '1831602312170614786', '检查是否配置远程日志功能', 'SBL-linux-04-06', 'A02', 'G3', '应对审计记录进行保护，定期备份，避免受到未预期的删除、修改或覆盖等', 7, '检查是否配置远程日志功能 ', 6, '1', '2024-09-05 15:56:36', '1', '2024-09-07 18:55:39', 0);
