INSERT INTO `hrtool_check_item` VALUES ('1831602313009475586', '1831602312170614786', '检查安全事件日志配置', 'SBL-linux-04-03', 'A02', 'G3', '应启用安全审计功能，审计覆盖到每个用户，对重要的用户行为和重要安全事件进行审计', 7, '检查是否配置安全事件日志 ', 3, '1', '2024-09-05 15:56:36', '1', '2024-09-07 16:23:01', 0);
