INSERT INTO `hrtool_reinforce_point` VALUES ('1831948369459085314', '1831602312355164161', '加固空口令账号', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\naccount_no_password=$(cat /etc/shadow | awk \'BEGIN{FS=\":\";ORS=\",\"}{if($2==\"\")print $1};\')\nif [ -z \"$account_no_password\" ];then\n    return_msg=\"未发现空口令账号无需加固;\"\nelse\n  return_msg=\"发现空口令账号，因高风险操作未执行加固，请确认后自行加固，空口令账号：$account_no_password\"\n  exit 1\nfi', '无', '1', '2024-09-06 14:51:42', '1', '2024-09-06 15:46:14', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831956118930612226', '1831602312401301506', '加固除root之外UID为0的用户', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 2.6 SBL-linux-02-06 检查是否设置除 root 之外 UID 为 0 的用户\ndangerous_account2=($(cat /etc/shadow | awk \'{FS=\":\";ORS=\" \"}{if($1~/\\s*[^#]/)if($1!=\"root\"){if($3==\"0\")print $1}}\'))\nif [ ${#dangerous_account2[@]} -eq 0 ]; then\n    return_msg=\"未发现除root之外UID为0的用户无需加固;\"\nelse\n  return_msg=\"发现除root之外UID为0的用户, 因高风险操作未执行加固，请确认后自行加固, 用户: ${dangerous_account2};\"\n  exit 1\nfi', '无', '1', '2024-09-06 15:22:30', '1', '2024-09-06 15:46:00', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831959566547857409', '1831602312439050241', '加固用户目录缺省访问权限设置', 4, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/login.defs\")\n# 备份文件\nbackup_file\n\nget_config(){\n  echo \"$(grep -Eis \"^umask[[:blank:]]+[[:digit:]]{3}\" /etc/login.defs)\"\n}\n\n# 2.1 SBL-linux-02-01 检查用户目录缺省访问权限设置\nif grep -Eiqs \"^umask[[:blank:]]+[[:digit:]]{3}\" /etc/login.defs;then\n  old_config_str=$(get_config)\n  if grep -Eiqs \"^umask[[:blank:]]+027\" /etc/login.defs;then\n    return_msg=\"现有配置符合要求无需加固, ${old_config_str};\"\n  else\n    sed -ri \"s~^(umask[[:blank:]]+[[:digit:]]{3})~#\\1\\nUMASK 027~i\" /etc/login.defs || { return_msg=\"加固操作失败\"; exit 1; }\n    return_msg=\"加固成功, 原配置: ${old_config_str}, 新配置: $(get_config)\"\n  fi\nelse\n  echo \"UMASK 027\" >> /etc/login.defs\n  return_msg=\"加固成功, 原配置: , 新配置: $(get_config)\"\nfi', '无', '1', '2024-09-06 15:36:11', '1', '2024-09-06 15:37:08', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831960272826707969', '1831889224311681026', '加固日志文件权限设置', 5, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/rsyslog.conf\" \"/etc/syslog.conf\" \"/etc/syslog-ng/syslog-ng.conf\")\n# 备份文件\nbackupFile\n\nsyslog_file=\"\"\nif [ -f /etc/rsyslog.conf ]; then\n    syslog_file=\"/etc/rsyslog.conf\"\nelif [ -f /etc/syslog.conf ]; then\n    syslog_file=\"/etc/syslog.conf\"\nelif [ -f /etc/syslog.conf ]; then\n    syslog_file=\"/etc/syslog-ng/syslog-ng.conf\"\nelse\n    returnMsg=\"加固失败，当前系统未适配\"\n    exit 1\nfi\n\nLOGDIR=$(cat \"$syslog_file\" | grep -v \"^[[:space:]]*#\" | sed \'/^#/d\' | sed \'/^$/d\' | awk \'(($2!~/@/) && ($2!~/\\*/) && ($2!~/-/) && ($2~/\\//)) {print $2}\');\nLOGDIR=($(ls -l $LOGDIR 2>/etc/null | grep -E \"^-[rwx-]{3,3}(r-x|rw[x-]{1,1}){1,2}\"  | awk \'{print $NF}\'));\n# 获取LOGDIR数组长度\nLOGDIR_LEN=${#LOGDIR[@]}\nif [ \"$LOGDIR_LEN\" -eq 0 ]; then\n  returnMsg=\"$syslog_file 中未找到相关配置项，无需加固\"\nelse\n  filepathstr=\"\"\n  for item in \"${LOGDIR[@]}\"; do\n    if [ -f \"$item\" ]; then\n      filepathstr+=\"$item；\"\n      chmod 640 \"$item\"\n    fi\n  done\n  returnMsg=\"加固成功, $filepathstr 文件权限已修改为640\"\nfi', '无', '1', '2024-09-06 15:39:00', '1', '2024-09-06 15:39:35', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831961219070078977', '1831602312564879361', '加固对系统账号进行登录限制', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 2.5 SBL-linux-02-05 检查是否对系统账号进行登录限制\ndangerous_account=($(cat /etc/shadow | awk \'{FS=\":\";ORS=\" \"}{if($1~/\\s*[^#]/)if($1==\"daemon\"||$1==\"bin\"||$1==\"sys\"||$1==\"adm\"||$1==\"lp\"||$1==\"uucp\"||$1==\"nuucp\"||$1==\"smmsp\"){if(!match($2,\"!!\")&&$2!=\"!\"&&$2!=\"!*\"&&$2!=\"*\"&&$2!=\"x\")print $1}}\'))\nif [ ${#dangerous_account[@]} -eq 0 ]; then\n    return_msg=\"未发现不必要登录权限的系统账号无需加固, 已检测系统账号：daemon、bin、sys、adm、lp、uucp、nuucp和smmsp;\"\nelse\n  return_msg=\"发现拥有不必要登录权限的系统账号，因高风险操作未执行加固，请确认后自行加固，不必要登录权限的系统账号：${dangerous_account}\"\n  exit 1\nfi', '无', '1', '2024-09-06 15:42:45', '1', '2024-09-06 15:43:25', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831961687099879425', '1831602312606822401', '加固与设备运行、维护等工作无关的账号', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 2.7 SBL-linux-02-07 检查是否删除与设备运行、维护等工作无关的账号\n# 待检测的账号\nrisk_account=(\"adm\" \"lp\" \"mail\" \"uucp\" \"operator\" \"games\" \"gopher\" \"ftp\" \"nobody\" \"nobody4\" \"noaccess\" \"listen\" \"webservd\" \"rpm\" \"dbus\" \"avahi\" \"mailnull\" \"smmsp\" \"nscd\" \"vcsa\" \"rpc\" \"rpcuser\" \"nfs\" \"sshd\" \"pcap\" \"ntp\" \"haldaemon\" \"distcache\" \"apache\" \"webalizer\" \"squid\" \"xfs\" \"gdm\" \"sabayon\" \"named\")\nrisk_account_total=()\n# 遍历危险文件\nfor username in \"${risk_account[@]}\"; do\n    shadow_line=$(grep \"^$username:\" /etc/shadow | awk -F: \'$2 != \"*\" && $2 != \"!\" {print $1}\')\n    if [[ -n \"$shadow_line\" ]]; then\n        risk_account_total+=(\"$username\")\n    fi\ndone\nif [ \"${#risk_account_total[@]}\" -eq 0 ]; then\n  return_msg=\"未发现与设备运行、维护等工作无关的账号无需加固, 已检测账号：${risk_account[*]};\"\nelse\n  return_msg=\"发现【${#risk_account_total[@]}】个与设备运行、维护等工作无关的账号, 因高风险操作未执行加固，请确认后自行加固, 账号: ${risk_account_total[*]};\"\n  exit 1\nfi', '无', '1', '2024-09-06 15:44:37', '1', '2024-09-06 15:45:35', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831962691673436162', '1831602312975921153', '加固对登录进行日志记录', 5, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/rsyslog.conf\" \"/etc/syslog.conf\")\n# 备份文件\nbackup_file\n\nsyslog_file=\"\"\nsyslog_service=\"\"\nif [ -f /etc/rsyslog.conf ]; then\n    syslog_file=\"/etc/rsyslog.conf\"\n    syslog_service=\"rsyslog\"\nelif [ -f /etc/syslog.conf ]; then\n    syslog_file=\"/etc/syslog.conf\"\n    syslog_service=\"syslog\"\nelse\n    return_msg=\"加固失败，当前系统未适配\"\n    exit 1\nfi\n\nfind_config_file() {\n    local log_files=($(awk \'!/^#/ && !/auth.none/ && !/authpriv.none/ && /auth|authpriv/ {print $2}\' $1))\n    local is_create=\"\"\n    local is_exist=\"\"\n    for log_file in \"${log_files[@]}\"; do\n      # 判断$syslog_file配置文件中是否配置认证日志配置\n      if [ -n \"$log_file\" ]; then\n        # 判断日志文件是否存在，不存在则创建日志文件\n        if [ ! -f \"$log_file\" ]; then\n          touch \"$log_file\"\n          chmod 775 \"$log_file\"\n          is_create=\"create\"\n        else\n          is_exist=\"exist\"\n        fi\n      fi\n    done\n    if [ \"$is_create\" = \"create\" ]; then\n      echo \"create\"\n    elif [ \"$is_exist\" = \"exist\" ]; then\n      echo \"exist\"\n    else\n      echo \"not_found\"\n    fi\n}\n\n# 重启日志服务\nrestart_log_service(){\n    systemctl start $syslog_service > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    if [ \"$(systemctl is-active $syslog_service)\" = \"active\" ] ; then\n      return_msg=\"已重启 $syslog_service 服务；\"\n    else\n      return_msg=\"加固失败，$syslog_service 服务启动失败\"\n      exit 1\n    fi\n}\ncheck_log_service_status() {\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" != \"inactive\" ]; then\n    return_msg=\"已重启 $syslog_service 服务；\"\n  else\n    return_msg=\"加固失败，$syslog_service 服务启动失败\"\n    exit 1\n  fi\n}\n# 加固\nreinforce(){\n  local log_config=\"$1\"\n  local log_file=\"/var/log/auth.log\"\n  echo \"auth,authpriv.*      $log_file\" >> \"$log_config\"\n  if [ ! -f \"$log_file\" ]; then\n      touch \"$log_file\"\n      chmod 775 \"$log_file\"\n      chown root:adm \"$log_file\"\n  fi\n  if command -v systemctl > /dev/null 2>&1; then\n    restart_log_service\n  elif command -v service > /dev/null 2>&1; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\n  return_msg+=\"加固成功，在 $log_config 中增加配置 auth,authpriv.*      $log_file\"\n  exit 0\n}\n\n# 4.1 检查是否对登录进行日志记录\n# 第一步 检查rsyslog或syslog服务状态，如果未启动，则重启rsyslog或syslog服务\nif command -v systemctl > /dev/null 2>&1; then\n  if [ \"$(systemctl is-active $syslog_service)\" != \"active\" ]; then\n    if [ \"$(systemctl list-unit-files | grep -Es \"^$syslog_service.service\")\" ] ; then\n      restart_log_service\n    else\n      return_msg=\"加固失败，未找到 $syslog_service 服务\"\n      exit 1\n    fi\n  fi\nelif command -v service > /dev/null 2>&1; then\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" = \"inactive\" ]; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\nelse\n  return_msg=\"加固失败，当前系统未适配\"\n  exit 1\nfi\n\n# 第二步 检查配置文件是否配置\nres=$(find_config_file \"$syslog_file\")\n# 判断$syslog_file配置文件中是否配置认证日志配置\nif [ \"$res\" = \"not_found\" ]; then\n    # 判断是否存在$IncludeConfig参数指定配置文件\n    include_config=$(awk \'/^\\$IncludeConfig/ {print $2}\' $syslog_file)\n    if [ -n \"$include_config\" ]; then\n      config_files=($(ls ${include_config} 2> /dev/null))\n      if [ -z \"$config_files\" ]; then\n        reinforce \"$syslog_file\"\n      fi\n      find=0\n      for file in \"${config_files[@]}\"; do\n        f=$(find_config_file \"$file\")\n        if [ \"$f\" = \"create\" ]; then\n          return_msg+=\"加固成功，已创建登录日志文件 $f\"\n          exit 0\n        elif [ \"$f\" = \"exist\" ]; then\n          find=1\n        fi\n      done\n      if [ \"$find\" -eq 0 ]; then\n        reinforce \"$syslog_file\"\n      else\n        return_msg+=\"当前系统已配置登录日志无需加固\"\n      fi\n    else\n      reinforce \"$syslog_file\"\n    fi\nelif [ \"$res\" = \"create\" ]; then\n    return_msg+=\"加固成功，已创建日志文件\"\nelif [ \"$res\" = \"exist\" ]; then\n  return_msg+=\"当前系统已配置登录日志无需加固\"\nfi', '无', '1', '2024-09-06 15:48:37', '1', '2024-09-06 15:48:37', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831963079814328322', '1831602313080778754', '加固配置su命令使用情况记录', 5, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/rsyslog.conf\" \"/etc/syslog.conf\")\n# 备份文件\nbackup_file\n\nsyslog_file=\"\"\nsyslog_service=\"\"\nif [ -f /etc/rsyslog.conf ]; then\n    syslog_file=\"/etc/rsyslog.conf\"\n    syslog_service=\"rsyslog\"\nelif [ -f /etc/syslog.conf ]; then\n    syslog_file=\"/etc/syslog.conf\"\n    syslog_service=\"syslog\"\nelse\n    return_msg=\"加固失败，当前系统未适配\"\n    exit 1\nfi\n\nfind_config_file() {\n    local log_files=($(awk \'!/^#/ && !/authpriv.none/ && /authpriv/ {print $2}\' $1))\n    local is_create=\"\"\n    local is_exist=\"\"\n    for log_file in \"${log_files[@]}\"; do\n      # 判断$syslog_file配置文件中是否配置认证日志配置\n      if [ -n \"$log_file\" ]; then\n        # 判断日志文件是否存在，不存在则创建日志文件\n        if [ ! -f \"$log_file\" ]; then\n          touch \"$log_file\"\n          chmod 775 \"$log_file\"\n          is_create=\"create\"\n        else\n          is_exist=\"exist\"\n        fi\n      fi\n    done\n    if [ \"$is_create\" = \"create\" ]; then\n      echo \"create\"\n    elif [ \"$is_exist\" = \"exist\" ]; then\n      echo \"exist\"\n    else\n      echo \"not_found\"\n    fi\n}\n\n# 重启日志服务\nrestart_log_service(){\n    systemctl start $syslog_service > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    if [ \"$(systemctl is-active $syslog_service)\" = \"active\" ] ; then\n      return_msg=\"已重启 $syslog_service 服务；\"\n    else\n      return_msg=\"加固失败，$syslog_service 服务启动失败\"\n      exit 1\n    fi\n}\ncheck_log_service_status() {\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" != \"inactive\" ]; then\n    return_msg=\"已重启 $syslog_service 服务；\"\n  else\n    return_msg=\"加固失败，$syslog_service 服务启动失败\"\n    exit 1\n  fi\n}\n# 加固\nreinforce(){\n  local log_config=\"$1\"\n  local log_file=\"/var/log/secure.log\"\n  echo \"authpriv.*      $log_file\" >> \"$log_config\"\n  if [ ! -f \"$log_file\" ]; then\n      touch \"$log_file\"\n      chmod 775 \"$log_file\"\n      chown root:adm \"$log_file\"\n  fi\n  if command -v systemctl > /dev/null 2>&1; then\n    restart_log_service\n  elif command -v service > /dev/null 2>&1; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\n  return_msg+=\"加固成功，在 $log_config 中增加配置 authpriv.*      $log_file\"\n  exit 0\n}\n\n# 4.3 检查是否配置su命令使用情况记录.sh\n\n# 第一步 检查配置文件是否配置\nres=$(find_config_file \"$syslog_file\")\n# 判断$syslog_file配置文件中是否配置认证日志配置\nif [ \"$res\" = \"not_found\" ]; then\n    # 判断是否存在$IncludeConfig参数指定配置文件\n    include_config=$(awk \'/^\\$IncludeConfig/ {print $2}\' $syslog_file)\n    if [ -n \"$include_config\" ]; then\n      config_files=($(ls ${include_config} 2> /dev/null))\n      if [ -z \"$config_files\" ]; then\n        reinforce \"$syslog_file\"\n      fi\n      find=0\n      for file in \"${config_files[@]}\"; do\n        f=$(find_config_file \"$file\")\n        if [ \"$f\" = \"create\" ]; then\n          return_msg+=\"加固成功，已创建authpriv.*日志文件 $f\"\n          exit 0\n        elif [ \"$f\" = \"exist\" ]; then\n          find=1\n        fi\n      done\n      if [ \"$find\" -eq 0 ]; then\n        reinforce \"$syslog_file\"\n      else\n        return_msg+=\"当前系统已配置su命令日志无需加固\"\n      fi\n    else\n      reinforce \"$syslog_file\"\n    fi\nelif [ \"$res\" = \"create\" ]; then\n    return_msg+=\"加固成功，已创建日志文件\"\nelif [ \"$res\" = \"exist\" ]; then\n  return_msg+=\"当前系统已配置su命令日志无需加固\"\nfi\n\n# 第二步 检查rsyslog或syslog服务状态，如果未启动，则重启rsyslog或syslog服务\nif command -v systemctl > /dev/null 2>&1; then\n  if [ \"$(systemctl is-active $syslog_service)\" != \"active\" ]; then\n    if [ \"$(systemctl list-unit-files | grep -Es \"^$syslog_service.service\")\" ] ; then\n      restart_log_service\n    else\n      return_msg=\"加固失败，未找到 $syslog_service 服务\"\n      exit 1\n    fi\n  fi\nelif command -v service > /dev/null 2>&1; then\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" = \"inactive\" ]; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\nelse\n  return_msg=\"加固失败，当前系统未适配\"\n  exit 1\nfi', '无', '1', '2024-09-06 15:50:09', '1', '2024-09-06 15:50:09', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831963630555803650', '1831602313198219265', '禁用不必要的系统服务', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 3.2 SBL-linux-03-02 检查是否禁用不必要的系统服务\nrisk_service_str=\"chargen-dgram|daytime-stream|echo-streamklogin|tcpmux-server|chargen-stream|discard-dgram|eklogin|krb5-telnet|tftp|cvs|discard-stream|ekrb5-telnet|kshell|time-dgram|daytime-dgram|echo-dgram|gssftp|rsync|time-stream\"\nuss=$(ps ax | grep -E \"${risk_service_str}\" | grep -v \".*grep.*-E.*chargen-dgram|daytime-stream.*\")\nif [ -z \"$uss\" ];then\n  return_msg=\"未发现开启了不必要的系统服务无需加固, 已检测服务：${risk_service_str};\"\nelse\n  return_msg=\"发现开启了不必要的系统服务, 因高风险操作未执行加固，请确认后自行加固, 服务: $uss;\"\nfi\n', '无', '1', '2024-09-06 15:52:20', '1', '2024-09-07 19:22:07', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831964126607749121', '1831602313441488898', '设置命令行界面超时退出', 5, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/profile\")\n# 备份文件\nbackupFile\n\n\n## SBL-linux-05-03 检查是否设置命令行界面超时退出\nif grep -Eqs \"^TMOUT=[[:digit:]]+$\" /etc/profile;then\n  TMOUT=$(grep -oP \'(?<=^TMOUT=)[[:digit:]]+\' /etc/profile)\n  if [ \"$TMOUT\" -le 600 ]; then\n    returnMsg=\"现有配置TMOUT=${TMOUT}符合要求, 无需加固;\"\n  else\n    sed -ri \"s~^(TMOUT=[[:digit:]]+)$~#\\1\\nTMOUT=600~\" /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    source /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    returnMsg=\"加固成功, 原配置：TMOUT=${TMOUT}， 新配置: TMOUT=600\"\n  fi\nelif grep -Eqs \"^export[[:blank:]]TMOUT=[[:digit:]]+$\" /etc/profile;then\n  TMOUT=$(grep -oP \'(?<=^export[[:blank:]]TMOUT=)[[:digit:]]+\' /etc/profile)\n  if [ \"$TMOUT\" -le 600 ]; then\n    returnMsg=\"现有配置TMOUT=${TMOUT}符合要求, 无需加固;\"\n  else\n    sed -ri \"s~^(export[[:blank:]]TMOUT=[[:digit:]]+)$~#\\1\\nexport TMOUT=600~\" /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    source /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    returnMsg=\"加固成功, 原配置：TMOUT=${TMOUT}， 新配置: TMOUT=600\"\n  fi\nelse\n  echo \"export TMOUT=600\" >> /etc/profile\n   source /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n  returnMsg=\"加固成功, TMOUT=600\"\nfi\n', '无', '1', '2024-09-06 15:54:19', '1', '2024-09-06 16:16:21', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831964583598141441', '1831602313592483842', '限制远程登录IP范围（入侵防范）', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\nres=$(awk \'{FS=\":\";}{if($1~/^[[:space:]]*[^#]/)print $3}\' /etc/hosts.allow | grep \"allow\")\n# 检查使用IP协议远程维护的设备是否配置SSH协议，禁用telnet协议（身份鉴别）.sh\nif [ -z \"$res\" ]; then\n  return_msg=\"加固失败，当前系统未限制远程登录IP范围，因高风险操作未执行加固，请确认后自行加固\"\n  exit 1\nelse\n  return_msg=\"已限制远程登录IP范围，无需加固\"\nfi', '无', '1', '2024-09-06 15:56:08', '1', '2024-09-06 16:16:57', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831964875202932737', '1831602313487626241', '禁止root用户远程登录（访问控制）', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\nres=$(awk \'/^[[:space:]]*[^#]*PermitRootLogin[[:space:]]+(NO|no)/ {print $0}\' /etc/ssh/sshd_config)\nif [ -n \"$res\" ]; then\n  return_msg=\"已禁止 root 用户远程登录（访问控制），无需加固\"\nelse\n  return_msg=\"加固失败，系统未禁止 root 用户远程登录（访问控制），因高风险操作未执行加固，请确认后自行加固\"\n  exit 1\nfi', '无', '1', '2024-09-06 15:57:17', '1', '2024-09-06 16:17:27', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831965229814558722', '1831602313756061697', '设置口令生存周期', 5, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/login.defs\")\n# 备份文件\nbackupFile\n\nif grep -Eqs \"^PASS_MAX_DAYS[[:blank:]]+[[:digit:]]+$\" /etc/login.defs;then\n  PASS_MAX_DAYS=$(grep -oP \'^PASS_MAX_DAYS[[:blank:]]+[[:digit:]]+\' /etc/login.defs|awk \'{print $2}\')\n  if [ \"$PASS_MAX_DAYS\" -le 90 ]; then\n    returnMsg=\"现有配置PASS_MAX_DAYS=${PASS_MAX_DAYS}符合要求, 无需加固;\"\n  else\n    sed -ri \"s~^(PASS_MAX_DAYS[[:blank:]]+[[:digit:]]+)$~#\\1\\nPASS_MAX_DAYS    90~\" /etc/login.defs || { returnMsg=\"加固操作失败\"; exit 1; }\n    returnMsg=\"加固成功, 原配置: PASS_MAX_DAYS=${PASS_MAX_DAYS}; 新配置: PASS_MAX_DAYS=90\"\n  fi\nelse\n  echo \"PASS_MAX_DAYS    90\" >> /etc/login.defs\n  returnMsg=\"加固成功, 原配置: ; PASS_MAX_DAYS=90\"\nfi', '无', '1', '2024-09-06 15:58:42', '1', '2024-09-06 16:04:56', 0);
