INSERT INTO `hrtool_reinforce_point` VALUES ('1831965916921245698', '1831613444012814337', '设置口令更改最小间隔天数', 5, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/login.defs\")\n# 备份文件\nbackupFile\n\nif grep -Eqs \"^PASS_MIN_DAYS[[:blank:]]+[[:digit:]]+$\" /etc/login.defs;then\n  PASS_MIN_DAYS=$(grep -oP \'^PASS_MIN_DAYS[[:blank:]]+[[:digit:]]+\' /etc/login.defs|awk \'{print $2}\')\n  if [ \"$PASS_MIN_DAYS\" -ge 3 ]; then\n    returnMsg=\"现有配置PASS_MIN_DAYS=${PASS_MIN_DAYS}符合要求, 无需加固;\"\n  else\n    sed -ri \"s~^(PASS_MIN_DAYS[[:blank:]]+[[:digit:]]+)$~#\\1\\nPASS_MIN_DAYS    3~\" /etc/login.defs || { returnMsg=\"加固操作失败\"; exit 1; }\n    returnMsg=\"加固成功, 原配置: PASS_MIN_DAYS=${PASS_MIN_DAYS}; 新配置: PASS_MIN_DAYS=3\"\n  fi\nelse\n  echo \"PASS_MIN_DAYS    3\" >> /etc/login.defs\n  returnMsg=\"加固成功, 原配置: ; 新配置: PASS_MIN_DAYS=3\"\nfi', '无', '1', '2024-09-06 16:01:26', '1', '2024-09-06 16:04:03', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831966263651774465', '1831614975294484481', '设置口令过期前警告天数', 1, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/login.defs\")\n# 备份文件\nbackupFile\n\nif grep -Eqs \"^PASS_WARN_AGE[[:blank:]]+[[:digit:]]+$\" /etc/login.defs;then\n  PASS_WARN_AGE=$(grep -oP \'^PASS_WARN_AGE[[:blank:]]+[[:digit:]]+\' /etc/login.defs|awk \'{print $2}\')\n  if [ \"$PASS_WARN_AGE\" -ge 15 ]; then\n    returnMsg=\"现有配置PASS_WARN_AGE=${PASS_WARN_AGE}符合要求, 无需加固;\"\n  else\n    sed -ri \"s~^(PASS_WARN_AGE[[:blank:]]+[[:digit:]]+)$~#\\1\\nPASS_WARN_AGE    15~\" /etc/login.defs || { returnMsg=\"加固操作失败\"; exit 1; }\n    returnMsg=\"加固成功, 原配置: PASS_WARN_AGE=${PASS_WARN_AGE}; 新配置: PASS_MIN_DAYS=15\"\n  fi\nelse\n  echo \"PASS_WARN_AGE    15\" >> /etc/login.defs\n  returnMsg=\"加固成功, 原配置: ; PASS_WARN_AGE=15\"\nfi\n', '无', '1', '2024-09-06 16:02:48', '1', '2024-09-06 16:03:28', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831966992835719170', '1831602313965776898', '设置密码重复使用次数限制', 1, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/pam.d/system-auth\" \"/etc/pam.d/common-password\" \"/etc/pam.d/passwd\")\n# 备份文件\nbackupFile\n\n## 1.6 SBL-linux-01-07 检查密码重复使用次数限制\nreinforce(){\n  local file=\"$1\";\n  local oldConfig=\"$2\";\n  if [ -n \"$oldConfig\" ];then\n    remember_value=$(echo \"$oldConfig\" |sed -r \'s~.*(remember=[[:digit:]]*).*~\\1~\'|awk -F \'=\' \'{print $2}\');\n    if [ \"$remember_value\" -ge 5 ]; then\n      returnMsg=\"当前配置符合要求无需加固, 配置信息：${oldConfig}\";\n    else\n      sed -ri \"s~^([[:space:]]*password[[:space:]]+sufficient[[:space:]]+.*remember=)[[:digit:]]+(.*)$~\\15 \\2~\" /etc/pam.d/${file};\n      returnMsg=\"加固成功, 原配置: ${oldConfig}，新配置: $(grep -Es \"^[[:space:]]*password[[:space:]]+sufficient[[:space:]]+.*remember=[[:digit:]]*\" /etc/pam.d/${file})\"\n    fi\n  else\n    has_config=`cat /etc/pam.d/${file} | grep -v \"^[[:space:]]*#\" | grep \"[[:space:]]*password[[:space:]]*sufficient[[:space:]]*.*\"`;\n    if [ -n \"$has_config\" ];then\n      sed -ri \"s~^([[:space:]]*password[[:space:]]+sufficient[[:space:]]+.*)(.*)$~\\1 remember=5~\" /etc/pam.d/${file};\n      returnMsg=\"加固成功, 原配置: ${has_config}，新配置: $(grep -Es \"^[[:space:]]*password[[:space:]]+sufficient[[:space:]]+.*remember=[[:digit:]]*\" /etc/pam.d/${file})\";\n    else\n      echo \"password sufficient pam_unix.so md5 shadow nullok try_first_pass use_authtok remember=5\" >> /etc/pam.d/${file};\n      returnMsg=\"加固成功, 原配置: ${has_config}，新配置：password sufficient pam_unix.so md5 shadow nullok try_first_pass use_authtok remember=5\";\n    fi\n  fi\n}\n\ncheck(){\n  local file=\"$1\";\n  local oldConfig=\"$2\";\n  if [ -n \"$oldConfig\" ];then\n    remember_value=$(echo \"$oldConfig\"|sed -r \'s~.*(remember=[[:digit:]]*).*~\\1~\'|awk -F \'=\' \'{print $2}\');\n    if [ \"$remember_value\" -ge 5 ]; then\n      echo \"ok\";\n    else\n      echo \"ng\";\n    fi\n  else\n    echo \"not_found\";\n  fi\n}\n\ncount=0;\nif [ -s /etc/pam.d/system-auth ];then\n  count=1;\n  red_ret=`cat /etc/pam.d/system-auth | grep -v \"^[[:space:]]*#\" | grep \"[[:space:]]*password[[:space:]]*sufficient[[:space:]]*.*remember.*\"`;\n  red_check=$(check \"system-auth\" \"${red_ret}\");\nfi\nif [ -s /etc/pam.d/common-password ];then\n  count=1;\n  suse_ret=`cat /etc/pam.d/common-password | grep -v \"^[[:space:]]*#\" | grep \"[[:space:]]*password[[:space:]]*sufficient[[:space:]]*.*remember.*\"`;\n  suse_check=$(check \"common-password\" \"${suse_ret}\");\nfi\nif [ -s /etc/pam.d/passwd ];then\n  count=1;\n  suse_ret2=`cat /etc/pam.d/passwd | grep -v \"^[[:space:]]*#\" | grep \"[[:space:]]*password[[:space:]]*sufficient[[:space:]]*pam_unix.so[[:space:]]*md5[[:space:]]*shadow[[:space:]]*nullok[[:space:]]*try_first_pass[[:space:]]*use_authtok[[:space:]]*\" | grep \"remember\"`;\n  suse2_check=$(check \"passwd\" \"${suse_ret2}\");\nfi\nif [ \"$count\" -gt 0 ] ;then\n  if [ \"$red_check\" = \"ok\" ] || [ \"$suse_check\" = \"ok\" ] || [ \"$suse2_check\" = \"ok\" ]; then\n    returnMsg=\"当前配置符合要求无需加固，${red_ret} ${suse_ret} ${suse_ret2}\";\n  else\n    if [ \"$red_check\" = \"ng\" ] ; then\n      reinforce \"system-auth\" \"${red_ret}\";\n    elif [ \"$suse_check\" = \"ng\" ]; then\n      reinforce \"common-password\" \"${suse_ret}\";\n    elif [ \"$suse2_check\" = \"ng\" ]; then\n      reinforce \"passwd\" \"${suse_ret2}\";\n    else\n      if [ -s /etc/pam.d/system-auth ] ; then\n        reinforce \"system-auth\" \"${red_ret}\";\n      elif [ -s /etc/pam.d/common-password ]; then\n        reinforce \"common-password\" \"${suse_ret}\";\n      elif [ -s /etc/pam.d/passwd ]; then\n        reinforce \"passwd\" \"${suse_ret2}\";\n      else\n        returnMsg=\"加固失败，未找到配置文件\";\n        exit 1;\n      fi\n    fi\n  fi\nelse\n  returnMsg=\"加固失败，未找到配置文件\"\n  exit 1;\nfi', '无', '1', '2024-09-06 16:05:42', '1', '2024-09-08 20:05:20', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831969413028818945', '1831602314020302850', '设置账户认证失败次数限制', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/pam.d/sshd\")\n#  \"/etc/pam.d/system-auth\" \"/etc/pam.d/passwd\" \"/etc/pam.d/common-auth\" \"/etc/pam.d/common-account\" \"/etc/pam.d/login\"\n# 备份文件\nbackupFile\n\n# SBL-linux-01-08 检查账户认证失败次数限制\n# centos系统\nos=$(grep -oP \'(?<=^ID=).+\' /etc/os-release | tr -d \'\"\')\nosVersion=$(grep -oP \'(?<=^VERSION_ID=).+\' /etc/os-release | tr -d \'\"\')\n\n\n# 判断是否为给定关键词的系统\n# $1参数1为关键词\n# 返回值 1 匹配 0 不匹配 -1 无法识别\nvalidate_os() {\n  # 检查 lsb_release 命令\n  if command -v lsb_release > /dev/null 2>&1; then\n      if [[ $(lsb_release -i) =~ $1 ]]; then\n          echo 1\n      else\n          echo 0\n      fi\n  else\n      # 检查 /etc/redhat-release 文件\n      if [ -f /etc/redhat-release ]; then\n          if grep -qi \"$1\" /etc/redhat-release; then\n              echo 1\n          else\n              echo 0\n          fi\n      else\n          # 检查 /etc/os-release 文件\n          if [ -f /etc/os-release ]; then\n              if grep -qi \"$1\" /etc/os-release; then\n                  echo 1\n              else\n                  echo 0\n              fi\n          else\n              echo -1\n          fi\n      fi\n  fi\n}\n\n\nget_config(){\n    if [ \"$osVersion\" -ge 6 ]; then\n      # centos 6及以上版本\n      echo \"$(grep -Es \"^auth[[:blank:]]+required[[:blank:]]+$1[[:blank:]]+.*\" /etc/pam.d/sshd)\"\n    else\n      # centos 6以下版本\n      echo \"$(grep -Es \"^auth[[:blank:]]+required[[:blank:]]+$1[[:blank:]]+deny=5[[:blank:]]+unlock_time=600[[:blank:]]+even_deny_root[[:blank:]]+root_unlock_time=10\" /etc/pam.d/sshd)\"\n    fi\n}\n\nget_config2(){\n    echo \"$(grep -Es \"^account[[:blank:]]+required[[:blank:]]+$1\" /etc/pam.d/sshd)\"\n}\n\nif [ \"$os\" = \"centos\" ]; then\n  pam_tally_file=\"\"\n  auth_required_rule=\"\"\n  if [ \"$osVersion\" -ge 6 ]; then\n      pam_tally_file=\"pam_tally2.so\"\n      auth_required_rule=\"deny=5 unlock_time=600 no_lock_time\"\n  else\n      pam_tally_file=\"pam_tally\"\n      auth_required_rule=\"deny=5 unlock_time=600 even_deny_root root_unlock_time=10\"\n  fi\n\n  oldConfigStr=$(get_config ${pam_tally_file})\n  #前缀是否存在\n  if grep -Eqs \"^auth[[:blank:]]+required[[:blank:]]+${pam_tally_file}[[:blank:]]+.*\" /etc/pam.d/sshd;then\n    if [ \"$osVersion\" -ge 6 ]; then\n      # 是否与目标相符\n      if grep -Eqs \"^auth[[:blank:]]+required[[:blank:]]+${pam_tally_file}[[:blank:]]+deny=5[[:blank:]]+unlock_time=600[[:blank:]]+no_lock_time\" /etc/pam.d/sshd;then\n       returnMsg=\"现有配置符合要求无需加固, ${oldConfigStr};\"\n      # 修改\n      else\n        sed -ri \"s~(^auth[[:blank:]]+required[[:blank:]]+${pam_tally_file}[[:blank:]]+.*)$~#\\1\\nauth required ${pam_tally_file} $auth_required_rule~\" /etc/pam.d/sshd || { returnMsg=\"加固操作失败\"; exit 1; }\n      fi\n    else\n      # 是否与目标相符\n      if grep -Eqs \"^auth[[:blank:]]+required[[:blank:]]+${pam_tally_file}[[:blank:]]+deny=5[[:blank:]]+unlock_time=600[[:blank:]]+even_deny_root[[:blank:]]+root_unlock_time=10\" /etc/pam.d/sshd;then\n        returnMsg=\"现有配置符合要求无需加固, ${oldConfigStr};\"\n      # 修改\n      else\n        sed -ri \"s~(^auth[[:blank:]]+required[[:blank:]]+${pam_tally_file}[[:blank:]]+.*)$~#\\1\\nauth required ${pam_tally_file} $auth_required_rule~\" /etc/pam.d/sshd || { returnMsg=\"加固操作失败\"; exit 1; }\n      fi\n    fi\n  else\n  #  不存在，添加\n    echo \"auth required ${pam_tally_file} $auth_required_rule\" >> /etc/pam.d/sshd\n  fi\n\n  # 判断returnMsg为空\n  if [ -z \"$returnMsg\" ]; then\n    returnMsg=\"加固成功, 原配置: ${oldConfigStr}, 新配置: $(get_config ${pam_tally_file})\"\n  fi\n  oldConfigStr2=$(get_config2 ${pam_tally_file})\n  if grep -Eqs \"^account[[:blank:]]+required[[:blank:]]+${pam_tally_file}\" /etc/pam.d/sshd;then\n    returnMsg+=\"; 现有配置符合要求无需加固, ${oldConfigStr2};\"\n  else\n    echo \"account required ${pam_tally_file}\" >> /etc/pam.d/sshd\n    returnMsg+=\"; 加固成功, 原配置: ${oldConfigStr2}, 新配置: $(get_config2 ${pam_tally_file})\"\n  fi\nelif [ \"$(validate_os \'red hat\')\" = \"1\" ]; then\n  returnMsg=\"加固失败，redhat 当前系统未适配\"\n  exit 1\nelse\n  returnMsg=\"加固失败，当前系统未适配\"\n  exit 1\nfi', '无', '1', '2024-09-06 16:15:19', '1', '2024-09-06 16:15:50', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1831974561025273858', '1831602313537957890', '使用IP协议远程维护设备配置SSH协议，禁用telnet协议', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 检查使用IP协议远程维护的设备是否配置SSH协议，禁用telnet协议（身份鉴别）.sh\n\n# 检测 telnet 进程是否存在\ntelnet_ps=$(ps aux | grep -E \'[t]elnet\');\nif [ -n \"$telnet_ps\" ]; then\n    telnet_exist=1\nelse\n    telnet_exist=0\nfi\n\n# 检测 sshd 进程是否存在\nsshd_ps=$(ps aux | grep -E \'[s]shd\');\nif [ -n \"$sshd_ps\" ]; then\n    sshd_exist=1\nelse\n    sshd_exist=0\nfi\nif [ \"$telnet_exist\" -eq 1 ] || [ \"$sshd_exist\" -eq 0 ] ; then\n  ret=\"\"\n  if [ \"$telnet_exist\" -eq 1 ] ; then\n    ret+=\"已检测到 Telnet 服务正在运行；\";\n  fi\n  if [ \"$sshd_exist\" -eq 0 ] ; then\n    ret+=\"未检测到 SSH 服务；\";\n  fi\n  return_msg=\"加固失败，$ret，因高风险操作未执行加固，请确认后自行禁用telnet服务\"\n  exit 1\nelse\n  return_msg=\"已检测到SSH服务，未发现Telnet服务，无需加固\"\nfi', '无', '1', '2024-09-06 16:35:46', '1', '2024-09-06 18:09:36', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832238405043859457', '1832237914872328193', '加固-检查共享文件夹的共享权限', 6, '{}', '# 1.1 检查共享文件夹的权限设置是否安全\n\n\n\n# Define the rollback function\nfunction rollback($originalPermissions) {\n    # Iterate over each saved original permission\n	try {\n		foreach ($item in $originalPermissions) {\n			$shareName = $item.ShareName;\n			$access = $item.Access;\n			# Reset the access for each user on the share\n			foreach ($userAccess in $access) {\n			\n				if ($userAccess.AccessControlType -eq \'Allow\') {\n					Grant-SmbShareAccess -Name $shareName -AccountName $userAccess.AccountName -AccessRight $userAccess.AccessRight -Force;\n				} elseif ($userAccess.AccessControlType -eq \"Deny\") {\n					Revoke-SmbShareAccess -Name $shareName -AccountName $userAccess.AccountName -Force;\n				}\n			\n			}\n		}\n		error_return \'加固失败，操作已回滚\' ;\n	}\n	catch {\n		error_return \'加固失败，操作回滚异常\';\n	}\n    \n};\n\n\nfunction error_return($message){\n	\'false|\'+$message;\n};\n\nfunction success_return($message){\n	 \'true|\'+$message;\n};\n\n$blockShareToUsername = \'Everyone\';\n$shares = Get-SmbShare;\n# 共享列表\n$shareToEveryone = @();\n$originalPermissions = @();\n\ntry {\n	foreach ($share in $shares)\n	{\n		$shareName = $share.Name;\n		# 共享文件夹权限\n		$access = Get-SmbShareAccess -Name $shareName;\n		$originalPermissions += [PSCustomObject]@{\n			ShareName = $shareName;\n			Access = $access;\n		}\n		foreach ($item in $access)\n		{\n			$shareAccount = $item.AccountName;\n			$shareAccess = $item.AccessControlType;\n			\n			if ($shareAccount -eq $blockShareToUsername -and $shareAccess -eq \'Allow\')\n			{\n				$shareToEveryone += $share;\n			}\n		}\n	}\n	if ($shareToEveryone.Count -eq 0)\n	{\n		success_return \'加固成功,当前系统以配置,无需加固\';\n	}\n	else\n	{\n		foreach ($item in $shareToEveryone)\n		{\n			$shareName = $item.Name;\n			Revoke-SmbShareAccess -Name $shareName -AccountName $blockShareToUsername -Force;\n		}\n		success_return \'加固成功,当前系统以加固成功\';\n	}\n}\ncatch {\n	rollback $originalPermissions;\n}\n\n\n\n', NULL, '1', '2024-09-07 10:04:12', '1', '2024-09-07 10:04:12', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832240683716947969', '1832237914918465538', '加固-检查是否已删除可匿名访问的共享和命名管道', NULL, '{}', '$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n    # 定义输出的 .inf 文件路径\n    $outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"rollback.inf\"\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n\n       \n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     \n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n# 1.2 检查是否已删除可匿名访问的共享和命名管道\n$key1 = \"Registry Values.MACHINE\\System\\CurrentControlSet\\Services\\LanManServer\\Parameters\\NullSessionShares\"\n$key2 = \"Registry Values.MACHINE\\System\\CurrentControlSet\\Services\\LanManServer\\Parameters\\NullSessionPipes\"\n$value1 = $wgp_kvPairs[$key1]\n$type1, $path1 = $value1 -split \',\', 2\n$value2 = $wgp_kvPairs[$key2]\n$type2, $path2 = $value2 -split \',\', 2\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1,$key2)\ntry {\n    if (\"\" -eq $path1 -and \"\" -eq $path2)\n    {\n        success_return \"配置项合规，无需加固\"\n    }\n    else\n    {\n    $wc = @\"\n[Registry Values]\nMACHINE\\System\\CurrentControlSet\\Services\\LanManServer\\Parameters\\NullSessionPipes=7,\nMACHINE\\System\\CurrentControlSet\\Services\\LanManServer\\Parameters\\NullSessionShares=7,\n\"@\n        $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n        $text | Set-Content -Path $winGbBaseLine\n        secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n        success_return \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}', NULL, '1', '2024-09-07 10:13:15', '1', '2024-09-07 10:13:15', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832243052651458561', '1832237915178512385', '加固-检查是否已删除活禁用高危账户', 6, '{}', '# 1.4 检查是否已删除或禁用高危帐户\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n$key1 = \"System Access.EnableGuestAccount\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if (\"0\" -eq $value1)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[System Access]\nEnableGuestAccount = 0\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}\n\n\n\n\n', NULL, '1', '2024-09-07 10:22:40', '1', '2024-09-07 10:22:40', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832248803197431810', '1832237915488890882', '加固-域环境：检查是否已正确配置“可被缓存保存的登录的 个数”策略', 2, '{}', '# 3.1 域环境：检查是否已正确配置“可被缓存保存的登录的个数”策略\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n\n       \n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n$key1 = \"Registry Values.MACHINE\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\CachedLogonsCount\"\n$value1 = $wgp_kvPairs[$key1]\n$type1, $path1 = $value1 -split \',\', 2\n$path1 = $path1 -replace \'\"\', \'\'\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$path1 -le 5)\n{   \n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[Registry Values]\nMACHINE\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\CachedLogonsCount=1,\"5\"\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n   rollback\n}\n\n\n\n\n\n', NULL, '1', '2024-09-07 10:45:31', '1', '2024-09-07 10:45:31', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832248979047821314', '1832237915526639618', '加固-检查是否已正确配置“锁定会话时显示用户信息”策略', 1, '{}', '# 3.2 检查是否已正确配置“锁定会话时显示用户信息”策略\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n\n       \n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n$key1 = \"Registry Values.MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\DontDisplayLockedUserId\"\n$value1 = $wgp_kvPairs[$key1]\n$type1, $path1 = $value1 -split \',\', 2\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ($path1 -eq \"3\")\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[Registry Values]\nMACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\DontDisplayLockedUserId=4,3\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n   rollback\n}', NULL, '1', '2024-09-07 10:46:13', '1', '2024-09-07 10:46:13', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832249173655138305', '1832237915568582658', '加固-检查是否已启用“不显示最后的用户名”策略', 1, '{}', '# 3.4 检查是否已启用“不显示最后的用户名”策略\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n\n       \n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n$key1 = \"Registry Values.MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\DontDisplayLastUserName\"\n$value1 = $wgp_kvPairs[$key1]\n$type1, $path1 = $value1 -split \',\', 2\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ($path1 -eq \"1\")\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[Registry Values]\nMACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\DontDisplayLastUserName=4,1\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n   rollback\n}', '1', '1', '2024-09-07 10:46:59', '1', '2024-09-09 14:24:55', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832249529600552961', '1832237915606331394', '加固-检查是否已禁用 Windows 硬盘默认共享', 6, '{}', '# 4.1 检查是否已禁用 Windows 硬盘默认共享\n$OutputEncoding = [System.Text.Encoding]::UTF8\n$path = \"Registry::HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\EventLog\\Application\"\n$valueName1 = \"AutoShareServer\"\n$valueName2 = \"AutoShareWks\"\n# 获取当前属性值\n$logProperty1 = Get-ItemProperty -Path $path -Name $valueName1\n$originalValue1 = $logProperty1.$valueName1\n\n$logProperty2 = Get-ItemProperty -Path $path -Name $valueName2\n$originalValue2 = $logProperty2.$valueName2\n\n# 定义目标值\n$targetValue1 = 0\n$targetValue2 = 0\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nfunction rollback {\n    Set-ItemProperty -Path $path -name $valueName1 -value $originalValue1\n    Set-ItemProperty -Path $path -name $valueName2 -value $originalValue2\n    error_return \"加固失败，操作已回滚\"\n}\n\ntry {\n    if ($null -ne $originalValue1 -and $originalValue1 -eq $targetValue1 -and $null -ne $originalValue2 -and $originalValue2 -eq $targetValue2)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    Set-ItemProperty -Path $path -name $valueName1 -value $targetValue1\n    Set-ItemProperty -Path $path -name $valueName2 -value $targetValue2\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}\n', NULL, '1', '2024-09-07 10:48:24', '1', '2024-09-07 10:48:24', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832264859693506562', '1831602312510353410', '删除潜在危险文件', 5, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 2.3 SBL-linux-02-03 检查是否删除了潜在危险文件\nrisk_file=(\".netrc\" \"hosts.equiv\" \".rhosts\")\ndangerous_files_total=()\n# 遍历危险文件\nfor item in \"${risk_file[@]}\"; do\n    risk_files=($(find / -maxdepth 3 -name \"$item\" 2> /dev/null))\n    for f in \"${risk_files[@]}\"; do\n      dangerous_files_total+=(\"$f\")\n      files+=(\"$f\")\n      # 通过备份文件替代删除\n      mv \"$f\" \"$f.$current_time.bak\"  2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        return_msg=\"加固失败, 无法危险删除文件：$f\"\n        exit 1\n      fi\n    done\ndone\nif [ \"${#dangerous_files_total[@]}\" -eq 0 ]; then\n    return_msg=\"未发现潜在危险文件无需加固, 已检测文件：${risk_file[*]};\"\nelse\n  return_msg=\"加固成功, 发现存在的潜在危险文件：${dangerous_files_total[*]}]\"\nfi', '无', '1', '2024-09-07 11:49:19', '1', '2024-09-07 11:50:00', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832304410153340930', '1832237914972991489', '加固-检查项是否已删除可远程访问的注册表路径和子路径', 6, '{}', '# 1.3 检查是否已删除可远程访问的注册表路径和子路径\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"Registry Values.MACHINE\\System\\CurrentControlSet\\Control\\SecurePipeServers\\Winreg\\AllowedExactPaths\\Machine\"\n$key2 = \"Registry Values.MACHINE\\System\\CurrentControlSet\\Control\\SecurePipeServers\\Winreg\\AllowedPaths\\Machine\"\n$value1 = $wgp_kvPairs[$key1]\n$type1, $path1 = $value1 -split \',\', 2\n$value2 = $wgp_kvPairs[$key2]\n$type2, $path2 = $value2 -split \',\', 2\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1,$key2)\ntry {\n    if (\"\" -eq $path1 -and \"\" -eq $path2)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[Registry Values]\nMACHINE\\System\\CurrentControlSet\\Control\\SecurePipeServers\\Winreg\\AllowedExactPaths\\Machine=7,\nMACHINE\\System\\CurrentControlSet\\Control\\SecurePipeServers\\Winreg\\AllowedPaths\\Machine=7,\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}\n\n\n', NULL, '1', '2024-09-07 14:26:29', '1', '2024-09-07 14:26:29', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832304664621764610', '1832237915254009857', '加固-检查是否已正确配置审核(日志记录)策略', 7, '{}', '# 2.1 检查是否已正确配置审核(日志记录)策略\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n$key1 = \"Event Audit.AuditSystemEvents\"\n$value1 = $wgp_kvPairs[$key1]\n$key2 = \"Event Audit.AuditLogonEvents\"\n$value2 = $wgp_kvPairs[$key2]\n$key3 = \"Event Audit.AuditObjectAccess\"\n$value3 = $wgp_kvPairs[$key3]\n$key4 = \"Event Audit.AuditPrivilegeUse\"\n$value4 = $wgp_kvPairs[$key4]\n$key5 = \"Event Audit.AuditPolicyChange\"\n$value5 = $wgp_kvPairs[$key5]\n$key6 = \"Event Audit.AuditAccountManage\"\n$value6 = $wgp_kvPairs[$key6]\n$key7 = \"Event Audit.AuditProcessTracking\"\n$value7 = $wgp_kvPairs[$key7]\n$key8 = \"Event Audit.AuditDSAccess\"\n$value8 = $wgp_kvPairs[$key8]\n$key9 = \"Event Audit.AuditAccountLogon\"\n$value9 = $wgp_kvPairs[$key9]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1,$key2,$key3,$key4,$key5,$key6,$key7,$key8,$key9)\ntry {\nif (\"3\" -eq $value1 -and \"3\" -eq $value2 -and \"3\" -eq $value3 -and \"3\" -eq $value4 -and \"3\" -eq $value5 -and \"3\" -eq $value6 -and \"3\" -eq $value7 -and \"3\" -eq $value8 -and \"3\" -eq $value9)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[Event Audit]\nAuditSystemEvents = 3\nAuditLogonEvents = 3\nAuditObjectAccess = 3\nAuditPrivilegeUse = 3\nAuditPolicyChange = 3\nAuditAccountManage = 3\nAuditProcessTracking = 3\nAuditDSAccess = 3\nAuditAccountLogon = 3\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}', NULL, '1', '2024-09-07 14:27:29', '1', '2024-09-07 14:27:29', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832304856548921346', '1832237915358867457', '加固-检查是否已正确配置应用程序日志', 7, '{}', '# 设置路径\n$OutputEncoding = [System.Text.Encoding]::UTF8\n$path = \"Registry::HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\EventLog\\Application\"\n\n# 获取当前属性值\n$logProperty = Get-ItemProperty -Path $path\n$originalValue1 = $logProperty.MaxSize\n$originalValue2 = $logProperty.AutoBackupLogFiles\n$originalValue3 = $logProperty.Retention\n\n# 定义目标值\n$targetValue1 = 8388608\n$targetValue2 = 0\n$targetValue3 = 0\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nfunction rollback {\n    Set-ItemProperty -Path $path -Name MaxSize -Value $originalValue1\n    Set-ItemProperty -Path $path -Name AutoBackupLogFiles -Value $originalValue2\n    Set-ItemProperty -Path $path -Name Retention -Value $originalValue3\n    error_return \"加固失败，操作已回滚\"\n}\n\ntry {\n    # 检查当前值并决定是否需要修改\nif ($originalValue1 -ge $targetValue1 -and $originalValue2 -eq $targetValue2 -and $originalValue3 -eq $targetValue3)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    # 修改注册表值\n    if ($originalValue1 -lt $targetValue1)\n    {\n        Set-ItemProperty -Path $path -Name MaxSize -Value $targetValue1\n    }\n    if ($originalValue2 -ne $targetValue2 -or $originalValue3 -ne $targetValue3)\n    {\n        Set-ItemProperty -Path $path -Name AutoBackupLogFiles -Value $targetValue2\n        Set-ItemProperty -Path $path -Name Retention -Value $targetValue3\n    }\n    success_return \"加固完成，配置项已修改完成，请及时重启\"\n}\n}\ncatch {\n    rollback\n}\n\n', NULL, '1', '2024-09-07 14:28:15', '1', '2024-09-07 14:28:15', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832304980536741890', '1832237915400810498', '加固-检查是否已正确配置系统日志', NULL, '{}', '# 2.3 检查是否已正确配置系统日志\n$OutputEncoding = [System.Text.Encoding]::UTF8\n$path = \"Registry::HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\EventLog\\System\"\n\n# 获取当前属性值\n$logProperty = Get-ItemProperty -Path $path\n$originalValue1 = $logProperty.MaxSize\n$originalValue2 = $logProperty.AutoBackupLogFiles\n$originalValue3 = $logProperty.Retention\n\n# 定义目标值\n$targetValue1 = 8388608\n$targetValue2 = 0\n$targetValue3 = 0\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nfunction rollback {\n    Set-ItemProperty -Path $path -Name MaxSize -Value $originalValue1\n    Set-ItemProperty -Path $path -Name AutoBackupLogFiles -Value $originalValue2\n    Set-ItemProperty -Path $path -Name Retention -Value $originalValue3\n    error_return \"加固失败，操作已回滚\"\n}\n\ntry {\n    # 检查当前值并决定是否需要修改\nif ($originalValue1 -ge $targetValue1 -and $originalValue2 -eq $targetValue2 -and $originalValue3 -eq $targetValue3)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    # 修改注册表值\n    if ($originalValue1 -lt $targetValue1)\n    {\n        Set-ItemProperty -Path $path -Name MaxSize -Value $targetValue1\n    }\n    if ($originalValue2 -ne $targetValue2 -or $originalValue3 -ne $targetValue3)\n    {\n        Set-ItemProperty -Path $path -Name AutoBackupLogFiles -Value $targetValue2\n        Set-ItemProperty -Path $path -Name Retention -Value $targetValue3\n    }\n    success_return \"加固完成，配置项已修改完成，请及时重启\"\n}\n}\ncatch {\n    rollback\n}\n', NULL, '1', '2024-09-07 14:28:45', '1', '2024-09-07 14:28:45', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832305077941063682', '1832237915446947842', '加固-检查是否已正确配置安全日志', NULL, '{}', '# 2.4 检查是否已正确配置安全日志\n$OutputEncoding = [System.Text.Encoding]::UTF8\n$path = \"Registry::HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\EventLog\\Security\"\n\n# 获取当前属性值\n$logProperty = Get-ItemProperty -Path $path\n$originalValue1 = $logProperty.MaxSize\n$originalValue2 = $logProperty.AutoBackupLogFiles\n$originalValue3 = $logProperty.Retention\n\n# 定义目标值\n$targetValue1 = 8388608\n$targetValue2 = 0\n$targetValue3 = 0\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nfunction rollback {\n    Set-ItemProperty -Path $path -Name MaxSize -Value $originalValue1\n    Set-ItemProperty -Path $path -Name AutoBackupLogFiles -Value $originalValue2\n    Set-ItemProperty -Path $path -Name Retention -Value $originalValue3\n    error_return \"加固失败，操作已回滚\"\n}\n\ntry {\n    # 检查当前值并决定是否需要修改\nif ($originalValue1 -ge $targetValue1 -and $originalValue2 -eq $targetValue2 -and $originalValue3 -eq $targetValue3)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    # 修改注册表值\n    if ($originalValue1 -lt $targetValue1)\n    {\n        Set-ItemProperty -Path $path -Name MaxSize -Value $targetValue1\n    }\n    if ($originalValue2 -ne $targetValue2 -or $originalValue3 -ne $targetValue3)\n    {\n        Set-ItemProperty -Path $path -Name AutoBackupLogFiles -Value $targetValue2\n        Set-ItemProperty -Path $path -Name Retention -Value $targetValue3\n    }\n    success_return \"加固完成，配置项已修改完成，请及时重启\"\n}\n}\ncatch {\n    rollback\n}\n', NULL, '1', '2024-09-07 14:29:08', '1', '2024-09-07 14:29:08', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832305344908513281', '1832237915648274434', '加固-检查是否已关闭不必要的端口-445', 6, '{}', '# 4.2 检查是否已关闭不必要的端口-445\n$serverName = \"LanmanServer\"\n$lanmanServer = Get-Service -Name $serverName\n$lanmanStatus = $lanmanServer.Status\n\n# 备份原始服务状态和启动类型\n$originalLanmanStatus = $lanmanStatus\n\n\n# 检查和修改注册表\n$path = \"Registry::HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Services\\NetBT\\Parameters\"\n$valueName = \"SMBDeviceEnabled\"\n\n# 备份原始注册表值\n$originalRegistryValue = (Get-ItemProperty -Path $path -Name $valueName).$valueName\n\n$value = Get-ItemProperty -Path $path -Name $valueName\n$outPut = \"\"\n$errorOutPut = \"\"\n\n\n# 回滚方法\nfunction rollback {\n\n    # 回滚服务状态\n    if ($originalLanmanStatus -ne \"Stopped\") {\n        Set-Service -Name $serverName -StartupType $originalLanmanStartupType\n        Start-Service -Name $serverName -ErrorAction SilentlyContinue\n        $errorOutPut += \"已回滚服务 $serverName 的状态和启动类型。\"\n    }\n\n    # 回滚注册表值\n    if ($null -ne $originalRegistryValue) {\n        Set-ItemProperty -Path $path -Name $valueName -Value $originalRegistryValue\n        $errorOutPut += \"已回滚注册表值 $valueName。\"\n    }\n\n    error_return \"加固失败，\"+$errorOutPut\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\ntry {\n    $anyDependentRunning = $false\n    if ($lanmanStatus -eq \"Stopped\") {\n        $outPut += \"服务项合规无需加固\"\n    } else {\n        $lanmanDependent = Get-Service -DependentServices -Name $serverName\n        if ($null -eq $lanmanDependent) {\n            Stop-Service -Name $serverName\n            Set-Service -Name \"LanmanServer\" -StartupType Disabled\n            $outPut +=  \"服务项加固完成\"\n        } else {\n            foreach ($item in $lanmanDependent) {\n                if ($item.Status -eq \"Running\") {\n                    $anyDependentRunning = $true\n                    break\n                }\n            }\n            if ($anyDependentRunning) {\n                $outPut +=  \"加固失败，服务项不合规，存在以下依赖，无法直接加固，请手动确认\"\n                $outPut +=  $lanmanDependent\n            } else {\n                Stop-Service -Name $serverName\n                Set-Service -Name \"LanmanServer\" -StartupType Disabled\n                $outPut +=  \"服务项加固完成\"\n            }\n        }\n        if ($null -ne $value.$valueName -and $value.$valueName -eq 0) {\n           $outPut += \";注册表合规无需加固\"\n        } else {\n            Set-ItemProperty -Path $path -name $valueName -value 0\n            $outPut +=  \";注册表加固完成\"\n        }\n    }\n    if (-not $anyDependentRunning) {\n        success_return $outPut    \n    }else{\n        error_return $outPut    \n    }\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-07 14:30:11', '1', '2024-09-07 14:30:40', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832305559157755906', '1832237915690217473', '加固-检查是否已关闭不必要的服务 -Simple TCP/IP Services', 6, '{}', '# 4.3 检查是否已关闭不必要的服务 -Simple TCP/IP Services\n$featureName = \"SimpleTCP\"\n$feature = Get-WindowsOptionalFeature -Online | Where-Object { $_.FeatureName -eq $featureName }\n$state = $feature.State\n\n# 回滚方法\nfunction rollback {\n    # 回滚服务状态\n    $errorOutPut = \"\"\n    if ($null -ne $originalServiceStatus -and $null -ne $originalServiceStartupType) {\n        Set-Service -Name $serviceName -StartupType $originalServiceStartupType\n        if ($originalServiceStatus -eq \"Running\") {\n            Start-Service -Name $serviceName -ErrorAction SilentlyContinue\n        } elseif ($originalServiceStatus -eq \"Stopped\") {\n            Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n        }\n\n        $errorOutPut += \"已回滚服务 $serviceName 的状态和启动类型。\"\n    }\n\n    $errorOutPut += \"回滚完成。\"\n    error_return $errorOutPut\n}\n\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\ntry{\n    $outPut = \"\";\n    if($null -ne $feature){\n    if ($state -eq \"Disabled\") {\n            $outPut += \"配置项合规，SimpleTCP功能未安装。\"\n        } elseif ($state -eq \"Enabled\") {\n            $serviceName = \"simptcp\"\n            $service = Get-Service -Name $serviceName\n\n            if ($service) {\n                # 备份原始服务状态和启动类型\n                $originalServiceStatus = $service.Status\n                $originalServiceStartupType = $service.StartType\n\n                $status = $service.Status\n                $startupType = $service.StartType\n\n                if ($status -eq \"Stopped\" -and $startupType -eq \"Disabled\") {\n                    $outPut += \"配置项合规 -Simple TCP/IP Services。\"\n                } else {\n                    # 修改服务状态\n                    Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n                    Set-Service -Name $serviceName -StartupType Disabled\n                    $outPut += \"加固完成，配置项已更新。\"\n                }\n            } else {\n                $outPut += \"配置项合规 -Simple TCP/IP Services找不到该服务。\"\n            }\n        }\n    }else{\n        $outPut += \"配置项合规 -Simple TCP/IP Services找不到该服务。\"\n    }\n\n    success_return $outPut\n}catch{\n    rollback\n}\n\n\n', '1', '1', '2024-09-07 14:31:03', '1', '2024-09-09 15:30:56', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832305645891768321', '1832237915774103553', '加固-检查是否已关闭不必要的服务-SimpleMail Transport Protocol (SMTP)', 6, '{}', '# 4.4 检查是否已关闭不必要的服务-SimpleMail Transport Protocol (SMTP)\n$serviceName = \"SMTPSVC\"\n$service = Get-Service -Name $serviceName\n\n# 回滚方法\nfunction rollback {\n    # 回滚服务状态\n    $errorOutPut = \"\"\n    if ($null -ne $originalServiceStatus -and $null -ne $originalServiceStartupType) {\n        # 根据备份的启动类型设置服务启动类型\n        if ($originalServiceStartupType -eq \"Auto\") {\n            Set-Service -Name $serviceName -StartupType Automatic\n        } elseif ($originalServiceStartupType -eq \"Manual\") {\n            Set-Service -Name $serviceName -StartupType Manual\n        } elseif ($originalServiceStartupType -eq \"Disabled\") {\n            Set-Service -Name $serviceName -StartupType Disabled\n        }\n\n        # 根据备份的状态启动或停止服务\n        if ($originalServiceStatus -eq \"Running\") {\n            Start-Service -Name $serviceName -ErrorAction SilentlyContinue\n        } elseif ($originalServiceStatus -eq \"Stopped\") {\n            Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n        }\n\n        $errorOutPut += \"已回滚服务 $serviceName 的状态和启动类型。\"\n    }\n\n    $errorOutPut += \"回滚完成。\"\n    error_return $errorOutPut\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\ntry {\n    $outPut = \"\"\n    if ($service) {\n        if ($service.Status -eq \"Stopped\") {\n            $outPut += \"4.4 检查是否已关闭不必要的服务-SimpleMail Transport Protocol (SMTP) [合规] []\"\n        } else {\n            # 备份原始服务状态和启动类型\n            $originalServiceStatus = $service.Status\n            $originalServiceStartupType = $service.StartType\n            # 修改服务状态\n            Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n            Set-Service -Name $serviceName -StartupType Disabled\n            $outPut += \"4.4 检查是否已关闭不必要的服务-SimpleMail Transport Protocol (SMTP) [不合规] [已修复]\"\n        }\n    }else{\n        $outPut += \"配置项合规 -SimpleMail Transport Protocol (SMTP)找不到该服务。\"\n    }\n\n    success_return $outPut\n} catch {\n    rollback\n}\n\n', '1', '1', '2024-09-07 14:31:23', '1', '2024-09-07 15:11:38', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832305815937241090', '1832237915828629505', '加固-4.5 检查是否已关闭不必要的服务-Windows Internet Name Service (WINS)', 6, '{}', '# 4.5 检查是否已关闭不必要的服务-Windows Internet Name Service (WINS)\n$featureName = \"WINSRuntime\"\n$feature = Get-WindowsOptionalFeature -Online | Where-Object { $_.FeatureName -eq $featureName }\n$state = $feature.State\n\n\n# 回滚方法\nfunction rollback {\n    # 回滚服务状态\n    $errorOutPut = \"\"\n    if ($null -ne $originalServiceStatus -and $null -ne $originalServiceStartupType) {\n        # 根据备份的启动类型设置服务启动类型\n        if ($originalServiceStartupType -eq \"Auto\") {\n            Set-Service -Name $serviceName -StartupType Automatic\n        } elseif ($originalServiceStartupType -eq \"Manual\") {\n            Set-Service -Name $serviceName -StartupType Manual\n        } elseif ($originalServiceStartupType -eq \"Disabled\") {\n            Set-Service -Name $serviceName -StartupType Disabled\n        }\n\n        # 根据备份的状态启动或停止服务\n        if ($originalServiceStatus -eq \"Running\") {\n            Start-Service -Name $serviceName -ErrorAction SilentlyContinue\n        } elseif ($originalServiceStatus -eq \"Stopped\") {\n            Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n        }\n\n        $errorOutPut += \"已回滚服务 $serviceName 的状态和启动类型。\"\n    }\n\n    $errorOutPut += \"回滚完成。\"\n    error_return $errorOutPut\n}\n\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\ntry {\n    $outPut = \"\"\n    if ($null -eq $feature -or $state -eq \"Disabled\") {\n        $outPut += \"无需加固,WINS功能未安装。\"\n    } elseif ($state -eq \"Enabled\") {\n        $serviceName = \"WINS\"\n        $service = Get-Service -Name $serviceName\n        \n        if ($service) {\n            # 备份原始服务状态和启动类型\n            $originalServiceStatus = $service.Status\n            $originalServiceStartupType = $service.StartType\n\n            $status = $service.Status\n            $startupType = $service.StartType\n\n            if ($status -eq \"Stopped\" -and $startupType -eq \"Disabled\") {\n                $outPut += \"无需加固，配置项合规。\"\n            } else {\n                # 修改服务状态\n                Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n                Set-Service -Name $serviceName -StartupType Disabled\n                $outPut += \"加固完成，配置已修改\"\n            }\n        } else {\n            $outPut += \"无需加固，服务不存在。\"\n        }\n    }\n    success_return $outPut\n} catch {\n    rollback\n}\n', '1', '1', '2024-09-07 14:32:04', '1', '2024-09-07 15:11:51', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832305921470124034', '1832237915870572545', '加固-检查是否已关闭不必要的服务-DHCP Server', 6, '{}', '# 4.6 检查是否已关闭不必要的服务-DHCP Server\n$featureName = \"DHCPServer\"\n$feature = Get-WindowsOptionalFeature -Online | Where-Object { $_.FeatureName -eq $featureName }\n$state = $feature.State\n\n# 回滚方法\nfunction rollback {\n    # 回滚服务状态\n    $errorOutPut = \"\"\n    if ($null -ne $originalServiceStatus -and $null -ne $originalServiceStartupType) {\n        # 根据备份的启动类型设置服务启动类型\n        if ($originalServiceStartupType -eq \"Auto\") {\n            Set-Service -Name $serviceName -StartupType Automatic\n        } elseif ($originalServiceStartupType -eq \"Manual\") {\n            Set-Service -Name $serviceName -StartupType Manual\n        } elseif ($originalServiceStartupType -eq \"Disabled\") {\n            Set-Service -Name $serviceName -StartupType Disabled\n        }\n\n        # 根据备份的状态启动或停止服务\n        if ($originalServiceStatus -eq \"Running\") {\n            Start-Service -Name $serviceName -ErrorAction SilentlyContinue\n        } elseif ($originalServiceStatus -eq \"Stopped\") {\n            Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n        }\n\n        $errorOutPut += \"已回滚服务 $serviceName 的状态和启动类型。\"\n    }\n\n    $errorOutPut += \"回滚完成。\"\n    error_return $errorOutPut\n}\n\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\ntry {\n    $outPut = \"\"\n    if ($null -eq $feature -or $state -eq \"Disabled\") {\n        $outPut += \"无需加固，DHCPServer功能未安装\"\n    } elseif ($state -eq \"Enabled\") {\n        $serviceName = \"DHCPServer\"\n        $service = Get-Service -Name $serviceName\n        \n        if ($service) {\n            # 备份原始服务状态和启动类型\n            $originalServiceStatus = $service.Status\n            $originalServiceStartupType = (Get-WmiObject -Class Win32_Service -Filter \"Name=\'$serviceName\'\").StartMode\n\n            $status = $service.Status\n            $startupType = $service.StartType\n\n            if ($status -eq \"Stopped\" -and $startupType -eq \"Disabled\") {\n                $outPut += \"无需加固，配置合规\"\n            } else {\n                # 修改服务状态\n                Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n                Set-Service -Name $serviceName -StartupType Disabled\n                $outPut += \"加固成功，配置已修改\"\n            }\n        } else {\n            $outPut += \"无需加固，该服务不存在\"\n        }\n    }\n    success_return $outPut\n} catch {\n    rollback\n}\n\n', '1', '1', '2024-09-07 14:32:29', '1', '2024-09-07 15:12:08', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832306026155757569', '1832237915912515585', '加固-检查是否已关闭不必要的服务 -DHCP Client', 6, '{}', '# 4.7 检查是否已关闭不必要的服务 -DHCP Client\n$service = Get-Service -Name \"dhcp\"\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\nif ($service)\n{\n    $status = $service.Status\n    $startupType = $service.StartType\n    if ($status -eq \"Stopped\" -and $startupType -eq \"Disabled\")\n    {\n        success_return \"无需加固,DHCP服务配置合规\"\n    }\n    else\n    {\n        error_return \"加固失败,已检测到DHCP服务正在运行,因高风险操作未执行加固,请确认后自行禁用DCHP服务\"\n    }\n}\nelse\n{\n    success_return \"无需加固,DHCP服务不存在\"\n}\n\n\n', '1', '1', '2024-09-07 14:32:54', '1', '2024-09-07 15:12:22', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832306126575783938', '1832237915954458626', '加固-检查是否已关闭不必要的服务 Remote Access Connection Manager', 6, '{}', '# 4.8 检查是否已关闭不必要的服务 -Remote Access Connection Manager\n$service = Get-Service -Name \"RasMan\"\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\nif ($service)\n{\n    $status = $service.Status\n    $startupType = $service.StartType\n    if ($status -eq \"Stopped\" -and $startupType -eq \"Disabled\")\n    {\n        success_return \"无需加固,Remote Access Connection Manager配置合规\"\n    }\n    else\n    {\n        error_return \"加固失败,已检测到服务正在运行,因高风险操作未执行加固,请确认后自行禁用Remote Access Connection Manager服务\"\n    }\n}\nelse\n{\n    success_return \"无需加固,Remote Access Connection Manager服务不存在\"\n}\n', '1', '1', '2024-09-07 14:33:18', '1', '2024-09-07 15:12:39', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832306374454956033', '1832237915996401666', '加固-检查是否已关闭不必要的服务 -Message Queuing', 6, '{}', '# 4.9 检查是否已关闭不必要的服务 -Message Queuing\n$serviceName = \"MSMQ\"\n$service = Get-Service -Name $serviceName\n# 回滚方法\nfunction rollback {\n    # 回滚服务状态\n    $errorOutPut = \"\"\n    if ($null -ne $originalServiceStatus -and $null -ne $originalServiceStartupType) {\n        # 根据备份的启动类型设置服务启动类型\n        if ($originalServiceStartupType -eq \"Auto\") {\n            Set-Service -Name $serviceName -StartupType Automatic\n        } elseif ($originalServiceStartupType -eq \"Manual\") {\n            Set-Service -Name $serviceName -StartupType Manual\n        } elseif ($originalServiceStartupType -eq \"Disabled\") {\n            Set-Service -Name $serviceName -StartupType Disabled\n        }\n\n        # 根据备份的状态启动或停止服务\n        if ($originalServiceStatus -eq \"Running\") {\n            Start-Service -Name $serviceName -ErrorAction SilentlyContinue\n        } elseif ($originalServiceStatus -eq \"Stopped\") {\n            Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n        }\n\n        $errorOutPut += \"已回滚服务 $serviceName 的状态和启动类型。\"\n    }\n\n    $errorOutPut += \"回滚完成。\"\n    error_return $errorOutPut\n}\n\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\ntry {\n    $outPut = \"\"\n    if ($service) {\n        # 备份原始服务状态和启动类型\n        $originalServiceStatus = $service.Status\n        $originalServiceStartupType = $service.StartType\n\n        $status = $service.Status\n        $startupType = $service.StartType\n\n        if ($status -eq \"Stopped\" -and $startupType -eq \"Disabled\") {\n            $outPut += \"无需加固,Message Queuing配置合规\"\n        } else {\n            # 修改服务状态\n            Stop-Service -Name $serviceName -ErrorAction SilentlyContinue\n            Set-Service -Name $serviceName -StartupType Disabled\n            $outPut += \"加固失败,已检测到服务正在运行,因高风险操作未执行加固,请确认后自行禁用Message Queuing服务\"\n        }\n    } else {\n        $outPut += \"无需加固,Message Queuing服务不存在\"\n    }\n    success_return $outPut\n} catch {\n    rollback\n}\n\n\n', '1', '1', '2024-09-07 14:34:17', '1', '2024-09-07 15:13:02', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832306506055438338', '1832237916038344705', '加固- 检查是否已启用 Windows 数据执行保护(DEP)', NULL, '{}', '# 获取当前 DEP 设置并备份\nfunction BackupCurrentDEPSettings {\n    # 获取当前 DEP 支持策略\n    $depSupportPolicy = wmic OS Get DataExecutionPrevention_SupportPolicy | Select-String -Pattern \"\\d\"\n\n    # 保存当前 DEP 设置到全局变量\n    $global:originalDEPSupportPolicy = $depSupportPolicy -replace \"\\D\", \"\"\n}\n\n# 回滚到原始 DEP 设置\nfunction RollbackDEPSettings {\n    if ($null -ne $global:originalDEPSupportPolicy) {\n        # 使用 bcdedit 命令将 DEP 设置回原始策略\n        switch ($global:originalDEPSupportPolicy) {\n            0 { bcdedit.exe /set nx AlwaysOff; error_return \"DEP 已回滚为 AlwaysOff。\" }\n            1 { bcdedit.exe /set nx OptIn; error_return \"DEP 已回滚为 OptIn。\" }\n            2 { bcdedit.exe /set nx OptOut; error_return \"DEP 已回滚为 OptOut。\" }\n            3 { bcdedit.exe /set nx AlwaysOn; error_return \"DEP 已回滚为 AlwaysOn。\" }\n            default { error_return \"未能识别的原始 DEP 设置: $global:originalDEPSupportPolicy，无法回滚。\" }\n        }\n    } else {\n        error_return \"没有原始 DEP 设置可用于回滚。\"\n    }\n}\n\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nBackupCurrentDEPSettings\n\n# 4.11 检查是否已启用 Windows 数据执行保护(DEP)\n# 检查是否硬件支持\n$r1 = wmic OS Get DataExecutionPrevention_Available\n$lines = $r1 -split \"`n\"\ntry {\n    foreach ($line in $lines)\n    {\n        if ($line -match \"TRUE\")\n        {\n            $depa = $true\n            # 检查是否已启用\n            $r2 = wmic OS Get DataExecutionPrevention_Drivers\n            $lines = $r2 -split \"`n\"\n            foreach ($line in $lines)\n            {\n                if ($line -match \"TRUE\")\n                {\n                    $depd = $true\n                    break\n                }\n                if ($line -match \"FALSE\")\n                {\n                    $depd = $false\n                    break\n                }\n            }\n            break\n        }\n        if ($line -match \"FALSE\")\n        {\n            $depa = $false\n            break\n        }\n    }\n    if (!$depa)\n    {\n        error_return \"加固失败,配置不合规,硬件不支持\"\n    }\n    else\n    {\n        if (!$depd)\n        {\n            error_return \"加固失败,配置不合规,DEP未启用\"\n        }\n        else\n        {\n            $r2 = wmic OS Get DataExecutionPrevention_SupportPolicy\n            $lines = $r2 -split \"`n\"\n            foreach ($line in $lines)\n            {\n                if ($line -match \"\\d\")\n                {\n                    if ($line -match 2)\n                    {\n                        success_return \"无需加固,DEP已启用\"\n                    }\n                    elseif ($line -match 0)\n                    {   \n                        bcdedit.exe /set nx OptIn\n                        success_return \"加固成功,配置已修改,请及时重新启动\"\n                    }\n                    else\n                    {\n                        error_return \"加固失败，当前状态：$line,请按需修改\"\n                    }\n                    break\n                }\n            }\n\n        }\n    }\n}\ncatch {\n    RollbackDEPSettings\n}\n', NULL, '1', '2024-09-07 14:34:48', '1', '2024-09-07 14:34:48', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832313668045819906', '1831602312669736962', '启用 cron 行为日志功能', 1, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/rsyslog.conf\" \"/etc/syslog.conf\")\n# 备份文件\nbackup_file\n\nsyslog_file=\"\"\nsyslog_service=\"\"\nif [ -f /etc/rsyslog.conf ]; then\n    syslog_file=\"/etc/rsyslog.conf\"\n    syslog_service=\"rsyslog\"\nelif [ -f /etc/syslog.conf ]; then\n    syslog_file=\"/etc/syslog.conf\"\n    syslog_service=\"syslog\"\nelse\n    return_msg=\"加固失败，当前系统未适配\"\n    exit 1\nfi\n\nfind_config_file() {\n    local log_files=($(awk \'!/^[[:space:]]*(#|\\$)/ && !/module\\(/ && !/cron.none/ && /cron/ {print $2}\' $1))\n    local is_create=\"\"\n    local is_exist=\"\"\n    for log_file in \"${log_files[@]}\"; do\n      # 判断$syslog_file配置文件中是否配置认证日志配置\n      if [ -n \"$log_file\" ]; then\n        # 判断日志文件是否存在，不存在则创建日志文件\n        if [ ! -f \"$log_file\" ]; then\n          touch \"$log_file\"\n          chmod 775 \"$log_file\"\n          is_create=\"create\"\n        else\n          is_exist=\"exist\"\n        fi\n      fi\n    done\n    if [ \"$is_create\" = \"create\" ]; then\n      echo \"create\"\n    elif [ \"$is_exist\" = \"exist\" ]; then\n      echo \"exist\"\n    else\n      echo \"not_found\"\n    fi\n}\n\n# 重启日志服务\nrestart_log_service(){\n    systemctl start $syslog_service > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    if [ \"$(systemctl is-active $syslog_service)\" = \"active\" ] ; then\n      return_msg=\"已重启 $syslog_service 服务；\"\n    else\n      return_msg=\"加固失败，$syslog_service 服务启动失败\"\n      exit 1\n    fi\n}\ncheck_log_service_status() {\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" != \"inactive\" ]; then\n    return_msg=\"已重启 $syslog_service 服务；\"\n  else\n    return_msg=\"加固失败，$syslog_service 服务启动失败\"\n    exit 1\n  fi\n}\n# 加固\nreinforce(){\n  local log_config=\"$1\"\n  local log_file=\"/var/log/cron.log\"\n  echo \"cron.*      $log_file\" >> \"$log_config\"\n  if [ ! -f \"$log_file\" ]; then\n      touch \"$log_file\"\n      chmod 775 \"$log_file\"\n      chown root:adm \"$log_file\"\n  fi\n  if command -v systemctl > /dev/null 2>&1; then\n    restart_log_service\n  elif command -v service > /dev/null 2>&1; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\n  return_msg+=\"加固成功，在 $log_config 中增加配置 cron.*      $log_file\"\n  exit 0\n}\n\n# 4.2 检查是否启用 cron 行为日志功能\n\n# 第一步 检查配置文件是否配置\nres=$(find_config_file \"$syslog_file\")\n# 判断$syslog_file配置文件中是否配置认证日志配置\nif [ \"$res\" = \"not_found\" ]; then\n    # 判断是否存在$IncludeConfig参数指定配置文件\n    include_config=$(awk \'/^\\$IncludeConfig/ {print $2}\' $syslog_file)\n    if [ -n \"$include_config\" ]; then\n      config_files=($(ls ${include_config} 2> /dev/null))\n      if [ -z \"$config_files\" ]; then\n        reinforce \"$syslog_file\"\n      fi\n      find=0\n      for file in \"${config_files[@]}\"; do\n        f=$(find_config_file \"$file\")\n        if [ \"$f\" = \"create\" ]; then\n          return_msg+=\"加固成功，已创建cron日志文件 $f\"\n          exit 0\n        elif [ \"$f\" = \"exist\" ]; then\n          find=1\n        fi\n      done\n      if [ \"$find\" -eq 0 ]; then\n        reinforce \"$syslog_file\"\n      else\n        return_msg+=\"当前系统已配置cron日志无需加固\"\n      fi\n    else\n      reinforce \"$syslog_file\"\n    fi\nelif [ \"$res\" = \"create\" ]; then\n    return_msg+=\"加固成功，已创建日志文件\"\nelif [ \"$res\" = \"exist\" ]; then\n  return_msg+=\"当前系统已配置cron日志无需加固\"\nfi\n\n# 第二步 检查rsyslog或syslog服务状态，如果未启动，则重启rsyslog或syslog服务\nif command -v systemctl > /dev/null 2>&1; then\n  if [ \"$(systemctl is-active $syslog_service)\" != \"active\" ]; then\n    if [ \"$(systemctl list-unit-files | grep -Es \"^$syslog_service.service\")\" ] ; then\n      restart_log_service\n    else\n      return_msg=\"加固失败，未找到 $syslog_service 服务\"\n      exit 1\n    fi\n  fi\nelif command -v service > /dev/null 2>&1; then\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" = \"inactive\" ]; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\nelse\n  return_msg=\"加固失败，当前系统未适配\"\n  exit 1\nfi', '无', '1', '2024-09-07 15:03:16', '1', '2024-09-07 16:15:19', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832332001365356546', '1831602313038835713', '安全事件日志配置', 1, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/rsyslog.conf\" \"/etc/syslog.conf\")\n# 备份文件\nbackup_file\n\nsyslog_file=\"\"\nsyslog_service=\"\"\nlog_facility=(\"kern\" \"daemon\")\nlog_facility_filter=(\"kern.debug\" \"daemon.notice\")\n\nif [ -f /etc/rsyslog.conf ]; then\n    syslog_file=\"/etc/rsyslog.conf\"\n    syslog_service=\"rsyslog\"\nelif [ -f /etc/syslog.conf ]; then\n    syslog_file=\"/etc/syslog.conf\"\n    syslog_service=\"syslog\"\nelse\n    return_msg=\"加固失败，当前系统未适配\"\n    exit 1\nfi\n\nfind_index() {\n    local search_str=\"$1\"\n    local index=-1\n\n    for i in \"${!log_facility[@]}\"; do\n        if [[ \"${log_facility[$i]}\" == \"$search_str\" ]]; then\n            index=$i\n            break\n        fi\n    done\n    echo $index\n}\n\nfind_config_file() {\n    local log_files=($(awk \'!/^[[:space:]]*(#|\\$)/ && !/module\\(/ && !/\'\"$2\"\'.none/ && /\'\"$2\"\'/ {print $2}\' $1))\n    local is_create=\"\"\n    local is_exist=\"\"\n    for log_file in \"${log_files[@]}\"; do\n      # 判断$syslog_file配置文件中是否配置认证日志配置\n      if [ -n \"$log_file\" ]; then\n        # 判断日志文件是否存在，不存在则创建日志文件\n        if [ ! -f \"$log_file\" ]; then\n          touch \"$log_file\"\n          chmod 775 \"$log_file\"\n          is_create=\"create\"\n        else\n          is_exist=\"exist\"\n        fi\n      fi\n    done\n    if [ \"$is_create\" = \"create\" ]; then\n      echo \"create\"\n    elif [ \"$is_exist\" = \"exist\" ]; then\n      echo \"exist\"\n    else\n      echo \"not_found\"\n    fi\n}\n\n# 重启日志服务\nrestart_log_service(){\n    systemctl start $syslog_service > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    if [ \"$(systemctl is-active $syslog_service)\" = \"active\" ] ; then\n      return_msg+=\"已重启 $syslog_service 服务；\"\n    else\n      return_msg=\"加固失败，$syslog_service 服务启动失败\"\n      exit 1\n    fi\n}\ncheck_log_service_status() {\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" != \"inactive\" ]; then\n    return_msg+=\"已重启 $syslog_service 服务；\"\n  else\n    return_msg=\"加固失败，$syslog_service 服务启动失败\"\n    exit 1\n  fi\n}\n# 加固\nreinforce(){\n  local log_config=\"$1\"\n  local facility=\"$2\"\n  # 根据facility的值查找log_facility所在下标，然后根据下标从数组log_facility_filter中获取值\n  local index=$(find_index \"$facility\")\n  local filter=\"${log_facility_filter[$index]}\"\n  local log_file=\"/var/log/messages.log\"\n  echo \"${filter}      $log_file\" >> \"$log_config\"\n  if [ ! -f \"$log_file\" ]; then\n      touch \"$log_file\"\n      chmod 666 \"$log_file\"\n  fi\n  if command -v systemctl > /dev/null 2>&1; then\n    restart_log_service\n  elif command -v service > /dev/null 2>&1; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\n  return_msg+=\"加固成功，在 $log_config 中增加配置 $filter      $log_file\"\n}\n# 第一步 检查配置文件是否配置\n# 第二参数：要检查的日志设施\ncheck_log_service_config() {\n  local facility=\"$1\"\n  local res=$(find_config_file \"$syslog_file\" \"$facility\")\n  # 判断$syslog_file配置文件中是否配置认证日志配置\n  if [ \"$res\" = \"not_found\" ]; then\n      # 判断是否存在$IncludeConfig参数指定配置文件\n      include_config=$(awk \'/^\\$IncludeConfig/ {print $2}\' $syslog_file)\n      if [ -n \"$include_config\" ]; then\n        config_files=($(ls ${include_config} 2> /dev/null))\n        if [ -z \"$config_files\" ]; then\n          reinforce \"$syslog_file\" \"$facility\"\n        fi\n        find=0\n        for file in \"${config_files[@]}\"; do\n          f=$(find_config_file \"$file\" \"$facility\")\n          if [ \"$f\" = \"create\" ]; then\n            return_msg+=\"加固成功，已创建$facility日志文件 $f；\"\n            find=1\n          elif [ \"$f\" = \"exist\" ]; then\n            find=1\n          fi\n        done\n        if [ \"$find\" -eq 0 ]; then\n          reinforce \"$syslog_file\" \"$facility\"\n        else\n          return_msg+=\"当前系统已配置$facility日志无需加固；\"\n        fi\n      else\n        reinforce \"$syslog_file\" \"$facility\"\n      fi\n  elif [ \"$res\" = \"create\" ]; then\n      return_msg+=\"加固成功，已创建日志文件\"\n  elif [ \"$res\" = \"exist\" ]; then\n    return_msg+=\"当前系统已配置$facility日志无需加固；\"\n  fi\n}\n\n\n# 遍历log_facility数组，判断日志设施是否配置\nfor facility in \"${log_facility[@]}\"; do\n  check_log_service_config \"$facility\"\ndone\n\n\n## SBL-linux-04-03 检查安全事件日志配置\n# 第二步 检查rsyslog或syslog服务状态，如果未启动，则重启rsyslog或syslog服务\nif command -v systemctl > /dev/null 2>&1; then\n  if [ \"$(systemctl is-active $syslog_service)\" != \"active\" ]; then\n    if [ \"$(systemctl list-unit-files | grep -Es \"^$syslog_service.service\")\" ] ; then\n      restart_log_service\n    else\n      return_msg=\"加固失败，未找到 $syslog_service 服务\"\n      exit 1\n    fi\n  fi\nelif command -v service > /dev/null 2>&1; then\n  if [ \"$(service $syslog_service status > /dev/null 2>&1 || echo \"inactive\")\" = \"inactive\" ]; then\n    service $syslog_service restart > /dev/null 2>&1 || { return_msg=\"加固失败，$syslog_service 服务启动失败\"; exit 1;}\n    check_log_service_status\n  fi\nelse\n  return_msg=\"加固失败，当前系统未适配\"\n  exit 1\nfi', '无', '1', '2024-09-07 16:16:07', '1', '2024-09-07 16:16:32', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832368335324889089', '1831602313135304706', '限制历史命令记录条数', 1, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/profile\")\n# 备份文件\nbackupFile\n\n\n## SBL-linux-04-05 检查历史命令设置\nif grep -Eqs \"^HISTSIZE=[[:digit:]]+$\" /etc/profile;then\n  histsize=$(grep -oP \'(?<=^HISTSIZE=)[[:digit:]]+\' /etc/profile)\n  if [ \"$histsize\" -le 5 ]; then\n    returnMsg=\"现有配置HISTSIZE=${histsize}符合要求, 无需加固;\"\n  else\n    sed -ri \"s~^(HISTSIZE=[[:digit:]]+)$~#\\1\\nHISTSIZE=5~\" /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    source /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    returnMsg=\"加固成功, 原配置：HISTSIZE=${histsize}， 新配置: HISTSIZE=5\"\n  fi\nelif grep -Eqs \"^export[[:blank:]]HISTSIZE=[[:digit:]]+$\" /etc/profile;then\n  histsize=$(grep -oP \'(?<=^export[[:blank:]]HISTSIZE=)[[:digit:]]+\' /etc/profile)\n  if [ \"$histsize\" -le 5 ]; then\n    returnMsg=\"现有配置HISTSIZE=${histsize}符合要求, 无需加固;\"\n  else\n    sed -ri \"s~^(export[[:blank:]]HISTSIZE=[[:digit:]]+)$~#\\1\\nexport HISTSIZE=5~\" /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    source /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n    returnMsg=\"加固成功, 原配置：HISTSIZE=${histsize}， 新配置: HISTSIZE=5\"\n  fi\nelse\n  echo \"export HISTSIZE=5\" >> /etc/profile\n   source /etc/profile || { returnMsg=\"加固操作失败\"; exit 1; }\n  returnMsg=\"加固成功, HISTSIZE=5\"\nfi\n', '无', '1', '2024-09-07 18:40:30', '1', '2024-09-07 18:41:19', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832372371088392194', '1831602312728457217', '配置远程日志功能', 1, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/rsyslog.conf\" \"/etc/syslog.conf\" \"/etc/syslog-ng/syslog-ng.conf\")\n# 备份文件\nbackup_file\n\nsyslog_file=\"\"\nsyslog_service=\"\"\nif [ -f /etc/rsyslog.conf ]; then\n    syslog_file=\"/etc/rsyslog.conf\"\n    syslog_service=\"rsyslog\"\nelif [ -f /etc/syslog.conf ]; then\n    syslog_file=\"/etc/syslog.conf\"\n    syslog_service=\"syslog\"\nelif [ -f /etc/syslog-ng/syslog-ng.conf ]; then\n    syslog_file=\"/etc/syslog-ng/syslog-ng.conf\"\n    syslog_service=\"syslog-ng\"\nelse\n    return_msg=\"加固失败，当前系统未适配\"\n    exit 1\nfi\n\nfind_config_file() {\n  if [ $syslog_service = \"syslog-ng\" ]; then\n      if [ -s /etc/syslog-ng/syslog-ng.conf ];then\n        ret_1=`cat /etc/syslog-ng/syslog-ng.conf | grep -v \"^[[:space:]]*#\" | grep \"port(514)\"`;\n        if [ -n \"$ret_1\" ];then\n          ret_2=`cat /etc/syslog-ng/syslog-ng.conf | grep -v \"^[[:space:]]*#\" | grep \"destination(logserver)\"`;\n        fi;\n      fi\n      if [ -n \"$ret_2\" ];then\n        echo \"exist\";\n      else\n        echo \"not_found\";\n      fi\n  else\n      if [ -n \"$(cat $1 | grep -v \"^[[:space:]]*#\" | grep -Es \'[[:space:]]*.+@.+\')\" ]; then\n        echo \"exist\"\n      else\n        echo \"not_found\"\n      fi\n  fi\n}\n\n# 加固\nreinforce(){\n  return_msg+=\"加固失败，远程日志服务器未知，请按根据实际远程日志服务器地址，在配置文件 $syslog_file 中进行配置\"\n  exit 1\n}\n\n# 4.2 检查是否配置远程日志功能\n# 第一步 检查配置文件是否配置\nres=$(find_config_file \"$syslog_file\")\n# 判断$syslog_file配置文件中是否配置远程日志\nif [ \"$res\" = \"not_found\" ]; then\n    # 判断是否存在$IncludeConfig参数指定配置文件\n    include_config=$(awk \'/^\\$IncludeConfig/ {print $2}\' $syslog_file)\n    if [ -n \"$include_config\" ]; then\n      config_files=($(ls ${include_config} 2> /dev/null))\n      if [ -z \"$config_files\" ]; then\n        reinforce \"$syslog_file\"\n      fi\n      find=0\n      for file in \"${config_files[@]}\"; do\n        f=$(find_config_file \"$file\")\n        if [ \"$f\" = \"exist\" ]; then\n          find=1\n          break\n        fi\n      done\n      if [ \"$find\" -eq 0 ]; then\n        reinforce \"$syslog_file\"\n      else\n        return_msg+=\"当前系统已配置远程日志功能无需加固\"\n      fi\n    else\n      reinforce \"$syslog_file\"\n    fi\nelif [ \"$res\" = \"exist\" ]; then\n  return_msg+=\"当前系统已配置远程日志功能无需加固\"\nfi', '无', '1', '2024-09-07 18:56:32', '1', '2024-09-07 18:57:05', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832378554985664513', '1831602313248550914', '关闭不必要的服务和端口', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 3.1 SBL-linux-03-01 检查是否关闭不必要的服务和端口\nrisk_service_list=()\nrisk_service_str=\"discard|kshell|daytime|echo|sendmail|ntalk|ident|printer|bootps|time|nfslock|lpd|nfs|chargen|ypbind|tftp|klogin|portmap\"\nif command -v systemctl > /dev/null 2>&1; then\n  risk_service_list=($(systemctl list-unit-files | awk \'/^(discard|kshell|daytime|echo|sendmail|ntalk|ident|printer|bootps|time|nfslock|lpd|nfs|chargen|ypbind|tftp|klogin|portmap)\\./ && $2 !=\"disabled\" {print $1}\'))\nelif command -v chkconfig > /dev/null 2>&1; then\n  risk_service_list=($(chkconfig --list |  awk \'/^(discard|kshell|daytime|echo|sendmail|ntalk|ident|printer|bootps|time|nfslock|lpd|nfs|chargen|ypbind|tftp|klogin|portmap) / { for (i=2; i<=7; i++) if ($i ~ /on|开/) { print $1;break; } }\'))\nelse\n  return_msg=\"加固失败，当前系统未适配\"\n  exit 1\nfi\n\nif [ \"${#risk_service_list[@]}\" -eq 0 ]; then\n  return_msg=\"未发现开启不必要的服务和端口无需加固, 已检测服务：${risk_service_str};\"\nelse\n  return_msg=\"发现开启了【${#risk_service_list[@]}】个不必要的服务和端口, 因高风险操作未执行加固，请确认后自行加固, 账号: ${risk_service_list[*]};\"\n  exit 1\nfi', '无', '1', '2024-09-07 19:21:06', '1', '2024-09-07 19:21:47', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832665997009936385', '1832665833901842433', '配置定时自动屏幕锁定（适用于图形界面的设备）', 1, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$return_msg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackup_file() {\n  for item in \"${files[@]}\"; do\n      backup_file=\"$item.$current_time.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backup_file}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  error_msg=\"\"\n  for item in \"${files[@]}\"; do\n    backup_file=\"$item.$current_time.bak\"\n    if [ -f \"${backup_file}\" ]; then\n      cp \"${backup_file}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        error_msg+=\"文件 ${backup_file} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$error_msg\" ]; then\n    error_return \"$return_msg $error_msg\";\n  else\n    error_return \"$return_msg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturn_msg=\"\"\ncurrent_time=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"\")\n# 备份文件\n#backup_file\n\n# 检查使用IP协议远程维护的设备是否配置SSH协议，禁用telnet协议（身份鉴别）.sh\n\nif command -v gsettings > /dev/null 2>&1; then\n  lock_delay=$(gsettings get org.gnome.desktop.screensaver lock-delay 2>&1) ;\n  idle_activation_enabled=$(gsettings get org.gnome.desktop.screensaver idle-activation-enabled  2>&1);\n  lock_enabled=$(gsettings get org.gnome.desktop.screensaver lock-enabled 2>&1) ;\n  idle_delay=$(gsettings get org.gnome.desktop.screensaver idle-delay 2>&1);\n  if [ -n \"$(echo \"$lock_delay\" | awk \' !/600$/ {print $0;}\')\" ] ; then\n      # 黑屏至锁屏延迟时间\n      gsettings set org.gnome.desktop.screensaver lock-delay 600\n  elif [ \"$idle_activation_enabled\" != \"true\" ]; then\n      # 启用空闲激活\n      gsettings set org.gnome.desktop.screensaver idle-activation-enabled true\n  elif [ \"$lock_enabled\" != \"true\" ]; then\n      # 启用屏幕锁定\n      gsettings set org.gnome.desktop.screensaver lock-enabled true\n  elif [ -n \"$(echo \"$idle_delay\" | awk \' !/600$/ {print $0;}\')\" ] ; then\n      # 启用空闲激活时间\n      gsettings set org.gnome.desktop.session idle-delay 600\n  fi\n  return_msg+=\"加固前配置：lock-delay=$lock_delay；idle-activation-enabled=$idle_activation_enabled；lock-enabled=$lock_enabled,idle-delay=$idle_delay；加固后配置：lock-delay=600；idle-activation-enabled=true；lock-enabled=true,idle-delay=600\"\n  return_msg=\"加固成功，$return_msg\"\nelif command -v gconftool-2 > /dev/null 2>&1; then\n  mode=$(gconftool-2 -g /apps/gnome-screensaver/mode 2>&1) ;\n  idle_activation_enabled=$(gconftool-2 -g /apps/gnome-screensaver/idle_activation_enabled  2>&1);\n  lock_enabled=$(gconftool-2 -g /apps/gnome-screensaver/lock_enabled  2>&1);\n  idle_delay=$(gconftool-2 -g /apps/gnome-screensaver/idle_delay  2>&1);\n  if [ \"$mode\" != \"blank-only\" ]; then\n    # 启用屏保\n    gconftool-2 --direct --config-source xml:readwrite:/etc/gconf/gconf.xml.mandatory --type string --set /apps/gnome-screensaver/mode blank-only\n    return_msg+=\"已启用屏保；\"\n  elif [ \"$idle_activation_enabled\" != \"true\" ]; then\n    # 启用空闲激活\n    gconftool-2 --direct --config-source xml:readwrite:/etc/gconf/gconf.xml.mandatory --type bool --set /apps/gnome-screensaver/idle_activation_enabled true\n    return_msg+=\"已启用空闲激活；\"\n  elif [ \"$lock_enabled\" != \"true\" ]; then\n    # 启用屏幕锁定\n    gconftool-2 --direct --config-source xml:readwrite:/etc/gconf/gconf.xml.mandatory --type bool --set /apps/gnome-screensaver/lock_enabled true\n    return_msg+=\"已启用屏幕锁定；\"\n  elif [ -n \"$(echo \"$idle_delay\" | awk \' !/15$/ {print $0;}\')\" ] ; then\n    # 启用空闲激活时间\n    gconftool-2 --direct --config-source xml:readwrite:/etc/gconf/gconf.xml.mandatory --type int --set /apps/gnome-screensaver/idle_delay 15\n    return_msg+=\"已启用空闲激活时间；\"\n  fi;\n  return_msg+=\"加固前配置：mode=$mode；idle_activation_enabled=$idle_activation_enabled；lock_enabled=$lock_enabled,idle_delay=$idle_delay；加固后配置：mode=blank-only；idle_activation_enabled=true；lock_enabled=true,idle_delay=15\"\n  return_msg=\"加固成功，$return_msg\"\nelse\n  return_msg=\"当前系统未检测到图形界面，无需加固\"\nfi', '无', '1', '2024-09-08 14:23:18', '1', '2024-09-08 14:23:40', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832713863493509122', '1832687947841200130', '设置账户认证失败次数限制', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 备份文件\nbackupFile;\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/pam.d/sshd\" \"/etc/pam.d/system-auth\" \"/etc/pam.d/common-auth\" \"/etc/pam.d/common-account\" \"/etc/pam.d/passwd\" \"/etc/pam.d/login\")\n\n# 定义函数检查pam模块是否存在\ncheck_pam_module() {\n    local module_name=$1;\n    if find /lib* -iname \"$module_name.so\" 2>/dev/null | grep -q .; then\n        echo \"found\";\n    else\n        res=$(check_pam_tally_command $module_name);\n        echo \"${res}\";\n    fi\n}\n\n# 定义函数检查pam_tally命令是否存在\ncheck_pam_tally_command() {\n    if command -v $1 >/dev/null 2>&1; then\n        echo \"found\";\n    else\n        echo \"not_found\";\n    fi\n}\n\n# 检查pam_tally模块是否安装\nhas_pam_tally=$(check_pam_module \"pam_tally\");\n# 检查pam_tally2模块是否安装\nhas_pam_tally2=$(check_pam_module \"pam_tally2\");\n\nreinforce(){\n  # 加固类型\n  local reinforceType=\"$1\";\n  if [ \"$has_pam_tally2\" = \"found\" ]; then\n    pam_tally_file=\"pam_tally2.so\";\n    auth_required_rule=\"deny=5 unlock_time=600 even_deny_root root_unlock_time=10\";\n  else\n    pam_tally_file=\"pam_tally.so\";\n    auth_required_rule=\"deny=5 unlock_time=600 no_lock_time\";\n  fi\n  if [ \"$reinforceType\" = \"ssh\" ]; then\n    exec_reinforce \"sshd\" \"sshd\" \"sshd\";\n  else\n    if [ -s /etc/pam.d/system-auth ];then\n      exec_reinforce \"system-auth\" \"system-auth\" \"账号\";\n    elif [ -s /etc/pam.d/common-auth ] && [ -s /etc/pam.d/common-account ];then\n      exec_reinforce \"common-auth\" \"common-account\" \"账号\";\n    elif [ -s /etc/pam.d/passwd ];then\n      exec_reinforce \"passwd\" \"passwd\" \"账号\";\n    elif [ -s /etc/pam.d/login ];then\n      exec_reinforce \"login\" \"login\" \"账号\";\n    else\n      returnMsg=\"$reinforceType 加固失败，未找到匹配的配置文件\";\n      exit 1;\n    fi\n  fi\n}\n\nexec_reinforce() {\n    local file1=\"$1\";\n    local file2=\"$2\";\n    local reinforceType=\"$3\";\n    ret1=$(find_auth_config \"${file1}\");\n    if [ -z \"$ret1\" ];then\n      sed -ri \"s~(^auth[[:blank:]]+required[[:blank:]]+.*)$~#\\1~\" /etc/pam.d/${file1};\n      echo \"auth required ${pam_tally_file} $auth_required_rule\" >> /etc/pam.d/${file1} || { returnMsg=\"$reinforceType 加固操作失败\"; exit 1; };\n    fi\n    ret2=$(find_account_config \"${file2}\");\n    if [ -z \"$ret2\" ];then\n      sed -ri \"s~(^account[[:blank:]]+required[[:blank:]]+.*)$~#\\1~\" /etc/pam.d/${file2};\n      echo \"account required ${pam_tally_file}\" >> /etc/pam.d/${file2} || { returnMsg=\"$reinforceType 加固操作失败\"; exit 1; };\n    fi\n    returnMsg+=\"已加固${reinforceType}认证失败次数限制；\";\n}\n\nfind_auth_config() {\n  local file=\"$1\";\n  echo `cat /etc/pam.d/${file} | grep -v \"^[[:space:]]*#\" | grep \"auth[[:space:]]*required[[:space:]]*pam_tally[0-9]*.so[[:space:]]*.*deny=[0-9]*[[:space:]]*.*unlock_time=[0-9]*\"`;\n}\nfind_account_config() {\n  local file=\"$1\";\n  echo `cat /etc/pam.d/${file}  | grep -v \"^[[:space:]]*#\" | grep \"account[[:space:]]*required[[:space:]]*pam_tally[2]\\?.so\"`;\n}\n\nif [ \"$has_pam_tally\" = \"not_found\" ] && [ \"$has_pam_tally2\" = \"not_found\" ]; then\n  returnMsg=\"加固失败，未安装pam_tally或pam_tally2模块\";\n  exit 1;\nelif [ \"$has_pam_tally2\" = \"found\" ]; then\n  # 检查是否配置SSH方式账户认证失败次数限制\n  if [ -s /etc/pam.d/sshd ];then\n    ret1=$(find_auth_config \"sshd\");\n  fi\n  if [ -s /etc/pam.d/sshd ];then\n    ret2=$(find_account_config \"sshd\");\n  fi;\n  if [[ -n \"$ret1\" && -n \"$ret2\" ]];then\n    returnMsg+=\"已配置sshd认证失败次数限制，无需加固；\";\n  else\n    reinforce \"ssh\";\n  fi\n  # 检查是否配置账户认证失败次数限制\n  if [ -s /etc/pam.d/system-auth ];then\n    red_ret=$(find_auth_config \"system-auth\");\n  fi\n  if [ -s /etc/pam.d/system-auth ];then\n    red_ret2=$(find_account_config \"system-auth\");\n  fi\n  if [ -s /etc/pam.d/common-auth ];then\n    suse_ret=$(find_auth_config \"common-auth\");\n  fi\n  if [ -s /etc/pam.d/common-account ];then\n    suse_ret2=$(find_account_config \"common-account\");\n  fi\n  if [ -s /etc/pam.d/passwd ];then\n    suse_ret3=$(find_auth_config \"passwd\");\n  fi\n  if [ -s /etc/pam.d/passwd ];then\n    suse_ret4=$(find_account_config \"passwd\");\n  fi\n  if [ -s /etc/pam.d/login ];then\n    ubuntu_ret=$(find_auth_config \"login\");\n  fi\n  if [ -s /etc/pam.d/login ];then\n    ubuntu_ret2=$(find_account_config \"login\");\n  fi\n  if [[ -n \"$red_ret\" && -n \"$red_ret2\" ]];then\n    returnMsg+=\"已配置账户认证失败次数限制，无需加固；\";\n  elif [[ -n \"$suse_ret\" && -n \"$suse_ret2\" ]];then\n    returnMsg+=\"已配置账户认证失败次数限制，无需加固；\";\n  elif [[ -n \"$suse_ret3\" && -n \"$suse_ret4\" ]];then\n    returnMsg+=\"已配置账户认证失败次数限制，无需加固；\";\n  elif [[ -n \"$ubuntu_ret\" && -n \"$ubuntu_ret2\" ]];then\n    returnMsg+=\"已配置账户认证失败次数限制，无需加固；\";\n  else\n    reinforce \"账号认证\";\n  fi\nfi;', '无', '1', '2024-09-08 17:33:30', '1', '2024-09-08 17:34:14', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832722313778749441', '1832721984899178497', '设置密码复杂度策略', 8, '{}', '#!/bin/bash\ntrap exit_handle EXIT\nexit_handle() {\n  # 判断是否报错\n  if [ \"$?\" -ne 0 ]; then\n    rollback\n  else\n    success_return \"$returnMsg\"\n    exit 0\n  fi\n}\n\n# 定义错误返回函数\nerror_return() {\n  echo \"false|$1\"\n}\n\n# 定义成功返回函数\nsuccess_return() {\n  echo \"true|$1\"\n}\n\n# 备份文件\nbackupFile() {\n  for item in \"${files[@]}\"; do\n      backupFile=\"$item.$currentTime.bak\"\n      # 文件存在则备份\n      if [ -f \"${item}\" ]; then\n          cp \"$item\" \"${backupFile}\"  2> /dev/null\n          if [ \"$?\" -ne 0 ]; then\n            exit 1\n          fi\n      fi\n  done\n}\n\n# 回滚\nrollback() {\n  errorMsg=\"\"\n  for item in \"${files[@]}\"; do\n    backupFile=\"$item.$currentTime.bak\"\n    if [ -f \"${backupFile}\" ]; then\n      cp \"${backupFile}\" \"$item\" 2> /dev/null\n      if [ \"$?\" -ne 0 ]; then\n        errorMsg+=\"文件 ${backupFile} 回滚出错;\"\n      fi\n    fi\n  done\n  if [ -n \"$errorMsg\" ]; then\n    error_return \"$returnMsg $errorMsg\";\n  else\n    error_return \"$returnMsg 操作已回滚\";\n  fi\n  exit 1;\n}\n\n# 返回信息\nreturnMsg=\"\"\ncurrentTime=$(date +\"%Y%m%d%H%M%S\")\n# 需要备份的文件\nfiles=(\"/etc/pam.d/system-auth\" \"/etc/pam.d/common-password\" \"/etc/pam.d/passwd\")\n#,\"/etc/pam.d/common-password\"\n# 备份文件\nbackupFile\n\nreinforce(){\n  local file=\"$1\";\n  if grep -Eqs \"^password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so.*\" /etc/pam.d/${file};then\n    # 计算密码复杂度策略的个数\n    count=0;\n    password_required_rule=(ucredit lcredit dcredit ocredit)\n    for item in \"${password_required_rule[@]}\"; do\n      if grep -Eqs \"^password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so[[:blank:]]+.*$item=-[1-9][[:digit:]]*.*\" /etc/pam.d/${file};then\n        ((count++))\n      fi\n    done\n    oldConfigStr=$(grep -Es \"^password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so.*\" /etc/pam.d/${file})\n    if [ \"$count\" -ge 3 ]; then\n      returnMsg=\"现有配置符合要求无需加固, ${oldConfigStr};\"\n    else\n      # 规则不足三个，添加规则\n      for item in \"${password_required_rule[@]}\"; do\n        if [ \"$count\" -ge 3 ]; then\n          break\n        fi\n        # 存在key\n        if grep -Eqs \"^password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so[[:blank:]]+.*$item=.*\" /etc/pam.d/${file};then\n          password_requisite_value=$(grep -Eo \"^password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so[[:blank:]]+.*\" /etc/pam.d/${file})\n          item_value=$(echo \"$password_requisite_value\"|sed -r \"s~.*($item=-?[[:digit:]]*).*~\\1~\"|awk -F \'=\' \'{print $2}\')\n          # 存在key，没有值，添加值\n          if [ -z \"$item_value\" ]; then\n            sed -ri \"s~^(password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so[[:blank:]]+.*$item=)(.*)$~\\1-1 \\2~\" /etc/pam.d/${file}\n          else\n            # 存在key，存在值，值>0，添加\n            if [ \"$item_value\" -gt 0 ]; then\n              sed -ri \"s~^(password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so[[:blank:]]+.*)$~\\1 $item=-1~\" /etc/pam.d/${file}\n            # 存在key，存在值，值=0，修改\n            elif [ \"$item_value\" -eq 0 ];then\n              sed -ri \"s~^(password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so[[:blank:]]+.*$item=)0(.*)$~\\1-1 \\2~\" /etc/pam.d/${file}\n            # 存在key，存在值，值<0，跳过\n            elif [ \"$item_value\" -lt 0 ];then\n              continue\n            fi\n          fi\n        else # 不存在key\n          sed -ri \"s~^(password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so[[:blank:]]+.*)~\\1 $item=-1~\" /etc/pam.d/${file}\n        fi\n        ((count++))\n      done\n      returnMsg=\"加固成功, 原配置: ${oldConfigStr}; 新配置: $(grep -Es \"^password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so.*\" /etc/pam.d/${file})\"\n    fi\n  else\n    echo \"password requisite pam_cracklib.so ucredit=-1 lcredit=-1 dcredit=-1\" >> /etc/pam.d/${file}\n    returnMsg=\"加固成功, 原配置: ${oldConfigStr}; 新配置: $(grep -Es \"^password[[:blank:]]+requisite[[:blank:]]+pam_cracklib.so.*\" /etc/pam.d/${file})\"\n  fi\n}\n\n\nif [ -s \"/etc/pam.d/system-auth\" ]; then\n  reinforce \"system-auth\";\nelif [ -s \"/etc/pam.d/common-password\" ]; then\n  reinforce \"common-password\";\nelif [ -s \"/etc/pam.d/passwd\" ]; then\n  reinforce \"passwd\";\nelse\n  echo \"加固失败，未找到配置文件\"\n  exit 1;\nfi', '无', '1', '2024-09-08 18:07:05', '1', '2024-09-08 20:08:33', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832954728803672065', '1832237915212066818', '加固-检查是否已正确配置“允许本地登录”策略', 6, '1', '# 5.1 检查是否已正确配置“允许本地登录”策略\n# 1.3 检查是否已删除可远程访问的注册表路径和子路径\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\nfunction error_return($message){\n	\"false|$message\"\n}\n$value1 = $wgp_kvPairs[\"Privilege Rights.SeInteractiveLogonRight\"]\nerror_return \"加固失败，当前允许在本地登录用户（组）：$value1，请手动确认并按需修改\"\n\n', '1', '1', '2024-09-09 09:30:37', '1', '2024-09-09 09:30:37', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832954906176593921', '1832237916176756738', '加固-检查是否已启用并正确配置屏幕保护程序', 6, '1', '# 5.3 检查是否已启用并正确配置屏幕保护程序\n$OutputEncoding = [System.Text.Encoding]::UTF8\n$path = \"Registry::HKEY_CURRENT_USER\\Control Panel\\Desktop\"\n\n# 获取当前属性值\n$screenSave = Get-ItemProperty -Path $path\n$originalValue1 = $screenSave.ScreenSaveActive\n$originalValue2 = $screenSave.ScreenSaverIsSecure\n$originalValue3 = $screenSave.ScreenSaveTimeOut\n$originalValue4 = $screenSave.SCRNSAVE.EXE\n\n# 定义目标值\n$targetValue1 = \"1\"\n$targetValue2 = \"1\"\n$targetValue3 = \"600\"\n$targetValue4 = \"C:\\\\Windows\\\\system32\\\\scrnsave.scr\"\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nfunction rollback {\n    Set-ItemProperty -Path $path -name \"ScreenSaveActive\" -value $originalValue1\n    Set-ItemProperty -Path $path -name \"ScreenSaverIsSecure\" -value $originalValue2\n    Set-ItemProperty -Path $path -name \"ScreenSaveTimeOut\" -value $originalValue3\n    Set-ItemProperty -Path $path -name \"SCRNSAVE.EXE\" -value $originalValue4\n    error_return \"加固失败，操作已回滚\"\n}\ntry {\n    if ($originalValue1 -eq $targetValue1 -and $originalValue2 -eq $targetValue2 -and [int]$originalValue3 -le 600)\n    {\n        success_return \"无需加固，配置项合规\"\n    }\n    else\n    {\n        Set-ItemProperty -Path $path -name \"ScreenSaveActive\" -value $targetValue1\n        Set-ItemProperty -Path $path -name \"ScreenSaverIsSecure\" -value $targetValue2\n        Set-ItemProperty -Path $path -name \"ScreenSaveTimeOut\" -value $targetValue3\n        Set-ItemProperty -Path $path -name \"SCRNSAVE.EXE\" -value $targetValue4\n        Write-Output \"加固成功，配置已修复，请及时重启\"\n    }\n}\ncatch {\n    rollback\n}\n\n\n\n', '1', '1', '2024-09-09 09:31:19', '1', '2024-09-09 09:31:19', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832955024212697089', '1832237916239671297', '加固-检查是否已正确配置服务器在暂停会话前所需的空闲时间量', 6, '1', '# 5.4 检查是否已正确配置服务器在暂停会话前所需的空闲时间量\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"Registry Values.MACHINE\\System\\CurrentControlSet\\Services\\LanManServer\\Parameters\\AutoDisconnect\"\n$value1 = $wgp_kvPairs[$key1]\n$type1, $path1 = $value1 -split \',\', 2\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$path1 -le 15)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[Registry Values]\nMACHINE\\System\\CurrentControlSet\\Services\\LanManServer\\Parameters\\AutoDisconnect=4,15\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 09:31:47', '1', '2024-09-09 09:31:47', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832955856870121474', '1832237916084482049', '加固-检查是否已禁止 Windows 自动登录\n', 6, '1', '# 6.1 检查是否已禁止 Windows 自动登录\n$OutputEncoding = [System.Text.Encoding]::UTF8\n$path = \"Registry::HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\"\n$valueName = \"AutoAdminLogon\"\n$value = Get-ItemProperty -Path $path -Name $valueName\n# 获取当前属性值\n$originalValue = $value.$valueName\n# 定义目标值\n$targetValue = 0\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nfunction rollback {\n    Set-ItemProperty -Path $path -name $valueName -value $originalValue\n    error_return \"加固失败，操作已回滚\"\n}\n\ntry {\n    if ($null -ne $value.$valueName -and $value.$valueName -eq 0)\n    {\n        Write-Output \"配置项合规，无需加固\"\n    }\n    else\n    {\n        Set-ItemProperty -Path $path -name $valueName -value $targetValue\n        Write-Output \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}\n\n', '1', '1', '2024-09-09 09:35:06', '1', '2024-09-18 11:28:41', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832956192280223746', '1832237916130619393', '加固-检查是否已修改默认的远程桌面(RDP)服务端口', 6, '1', '# 6.11 检查是否已修改默认的远程桌面(RDP)服务端口\n$path = \"Registry::HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Terminal Server\\WinStations\\RDP-Tcp\"\n$valueName = \"PortNumber\"\n$originalValue = Get-ItemProperty -Path $path -Name $valueName\n$targetValue = 31111\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\nfunction rollback {\n    Set-ItemProperty -Path $path -name $valueName -value $originalValue\n    netsh advfirewall firewall add rule name = \"Remote Desktop (TCP-In)PORT\" dir = in localport = $originalValue protocol = tcp action = allow\n    netsh advfirewall firewall add rule name = \"Remote Desktop (UDP-In)PORT\" dir = in localport = $originalValue protocol = udp action = allow\n    error_return \"加固失败，操作已回滚\"\n}\n\ntry {\n    if ($null -ne $originalValue.$valueName)\n    {\n        if ($originalValue.$valueName -eq 3389)\n        {\n            Set-ItemProperty -Path $path -name $valueName -value $targetValue\n            netsh advfirewall firewall add rule name = \"Remote Desktop (TCP-In)PORT\" dir = in localport = $targetValue protocol = tcp action = allow\n            netsh advfirewall firewall add rule name = \"Remote Desktop (UDP-In)PORT\" dir = in localport = $targetValue protocol = udp action = allow\n            success_return \"加固完成，配置已修复，新远程端口为 31111\"\n        }\n        else\n        {\n            success_return \"无需加固，配置项合规\"\n        }\n    }\n}\ncatch {\n    rollback\n}\n\n\n', '1', '1', '2024-09-09 09:36:26', '1', '2024-09-09 09:36:26', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832958404075134978', '1832237916285808641', '加固-检查是否已启用密码复杂性要求', 6, '1', '# 6.2 检查是否已启用密码复杂性要求\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.PasswordComplexity\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ($value1 -eq \"1\")\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[System Access]\nPasswordComplexity = 1\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 09:45:13', '1', '2024-09-09 09:45:24', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832964803660292098', '1832237916336140289', '加固-检查', 6, '1', '# 6.3 检查是否已正确配置密码长度最小值\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.MinimumPasswordLength\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$value1 -ge 10)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[System Access]\nMinimumPasswordLength = 10\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 10:10:39', '1', '2024-09-09 10:10:39', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832964905745457153', '1832237916382277634', '加固-检查是否已正确配置“提示用户在密码过期之前进行更改”策略', 6, NULL, '# 6.4 检查是否已正确配置“提示用户在密码过期之前进行更改”策略\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"Registry Values.MACHINE\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\PasswordExpiryWarning\"\n$value1 = $wgp_kvPairs[$key1]\n$type1, $path1 = $value1 -split \',\', 2\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$path1 -ge 15)\n{\n    success_return \"配置项合规，无需加固\"\n}\nelse\n{\n    $wc = @\"\n[Registry Values]\nMACHINE\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\\PasswordExpiryWarning=4,15\n\"@\n    $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n    $text | Set-Content -Path $winGbBaseLine\n    secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n    success_return \"加固完成，配置项已修改完成\"\n}\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 10:11:03', '1', '2024-09-09 10:11:03', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832965023752200194', '1832237916432609282', '加固-检查是否已正确配置密码最长使用期限', 6, '1', '# 6.5 检查是否已正确配置密码最长使用期限\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.MaximumPasswordAge\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$value1 -le 90)\n    {\n        success_return \"配置项合规，无需加固\"\n    }\n    else\n    {\n        $wc = @\"\n[System Access]\nMaximumPasswordAge = 90\n\"@\n        $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n        $text | Set-Content -Path $winGbBaseLine\n        secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n        success_return \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 10:11:31', '1', '2024-09-09 10:11:31', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832965195311816706', '1832237916482940929', '加固-检查是否已正确配置密码最短使用期限', 6, '1', '# 6.6 检查是否已正确配置密码最短使用期限\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.MinimumPasswordAge\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$value1 -gt 0)\n    {\n        success_return \"配置项合规，无需加固\"\n    }\n    else\n    {\n        $wc = @\"\n[System Access]\nMinimumPasswordAge = 3\n\"@\n        $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n        $text | Set-Content -Path $winGbBaseLine\n        secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n        success_return \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}\n', '1', '1', '2024-09-09 10:12:12', '1', '2024-09-09 10:12:12', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832965324563488770', '1832237916533272578', '加固-检查是否已正确配置“强制密码历史”', 6, '1', '# 6.7 检查是否已正确配置“强制密码历史”\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.PasswordHistorySize\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$value1 -ge 5)\n    {\n        success_return \"配置项合规，无需加固\"\n    }\n    else\n    {\n        $wc = @\"\n[System Access]\nPasswordHistorySize = 5\n\"@\n        $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n        $text | Set-Content -Path $winGbBaseLine\n        secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n        success_return \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 10:12:43', '1', '2024-09-09 10:12:43', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832965434622025730', '1832237916591992833', '加固-检查是否已正确配置帐户锁定时间', 6, '1', '# 6.8 检查是否已正确配置帐户锁定时间\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.LockoutDuration\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$value1 -ge 30)\n    {\n        success_return \"配置项合规，无需加固\"\n    }\n    else\n    {\n        $wc = @\"\n[System Access]\nLockoutDuration = 30\n\"@\n        $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n        $text | Set-Content -Path $winGbBaseLine\n        secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n        success_return \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 10:13:09', '1', '2024-09-09 10:13:09', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832965612758310914', '1832237916646518786', '加固-检查是否已正确配置帐户锁定阈值', 6, '1', '# 6.9 检查是否已正确配置帐户锁定阈值\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.LockoutBadCount\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$value1 -ge 5 )\n    {\n        success_return \"配置项合规，无需加固\"\n    }\n    else\n    {\n        $wc = @\"\n[System Access]\nLockoutBadCount = 5\n\"@\n        $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n        $text | Set-Content -Path $winGbBaseLine\n        secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n        success_return \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 10:13:52', '1', '2024-09-09 10:13:52', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832965895894802434', '1832237916705239041', '加固-检查是否已正确配置\'复位帐户锁定计数器\'时间', 6, '1', '# 6.10 检查是否已正确配置\'复位帐户锁定计数器\'时间\n$OutputEncoding = [System.Text.Encoding]::UTF8\n\n# 获取当前工作目录路径\n$currentDirectory = Get-Location\n\n# 定义输出的文件路径和日志文件路径\n$outputFilePath = Join-Path -Path $currentDirectory -ChildPath \"windows_gp_current.inf\"\n # 使用secedit将回滚文件应用到安全数据库中\n$outputInfPath = Join-Path -Path (Get-Location) -ChildPath \"./rollback.inf\"\n$seceditDbPath = Join-Path -Path (Get-Location) -ChildPath \"secedit.sdb\"\n$logFilePath = Join-Path -Path (Get-Location) -ChildPath \"secedit.log\"\n$winGbBaseLine = Join-Path -Path (Get-Location) -ChildPath \"./wingpbaseline.inf\"\n\n\n# 读取文件内容\n$wgp_content = Get-Content -Path $outputFilePath\n# 创建一个关联数组用于存储键值对\n$wgp_kvPairs = @{ }\n# 遍历文件内容的每一行\nforeach ($line in $wgp_content)\n{\n    # 检查行是否以 \"[\" 开头和 \"]\" 结尾，表示一个分类\n    if ($line -match \'^\\[.*\\]$\')\n    {\n        # 提取分类名称\n        $category = $line.TrimStart(\'[\').TrimEnd(\']\')\n    }\n    # 检查行是否包含 \"=\"，表示一个键值对\n    elseif ($line -match \'=\')\n    {\n        # 使用 \"=\" 分割键和值\n        $key, $value = $line -split \'=\', 2\n        $key = $key.Trim()\n        $value = $value.Trim()\n\n        # 根据分类和键存储值到关联数组中\n        $wgp_kvPairs[\"$category.$key\"] = $value\n    }\n}\n\n$wge_head = @\"\n[Unicode]\nUnicode=yes\n\"@\n\n$wge_feet = @\'\n[Version]\nsignature=\"$CHICAGO$\"\nRevision=1\n\'@\n\nfunction Backup-MultipleKeyValuesToInf {\n    param (\n        [string[]]$keysToBackup # 需要备份的多个key的数组\n    )\n\n\n    # 按分类分组要备份的键\n    $groupedKeys = $keysToBackup | Group-Object { $_ -split \'\\.\' | Select-Object -First 1 }\n\n    # 遍历每个分类\n    foreach ($group in $groupedKeys) {\n        $category = $group.Name\n\n        # 添加分类的标题\n        $backupContent += @\"\n[$category]\n\"@\n        $backupContent += \"`r`n\" # 添加分类之间的空行\n\n        $totalGroups = $group.Group.Count\n        $currentGroupIndex = 0\n        # 遍历分类下的每个键\n        foreach ($keyToBackup in $group.Group) {\n            $currentGroupIndex ++\n            # 检查是否存在该键\n            if ($wgp_kvPairs.ContainsKey($keyToBackup)) {\n                # 获取要备份的值\n                $valueToBackup = $wgp_kvPairs[$keyToBackup]\n\n                # 获取键名（去除分类前缀）\n                $keyName = $keyToBackup -split \'\\.\' | Select-Object -Last 1\n                $backupContent += \"$keyName=$valueToBackup\"\n                if ($currentGroupIndex -lt $totalGroups) {\n                     $backupContent += \"`r`n\"\n                }\n            } \n        }\n    }\n    # 如果有要备份的内容，则写入到 .inf 文件中\n    if ($backupContent -ne \"\") {\n        $infContent = $wge_head + [Environment]::NewLine + $backupContent + [Environment]::NewLine + $wge_feet\n        $infContent | Set-Content -Path $outputInfPath\n    }\n}\n\nfunction rollback {\n     # 配置命令\n     secedit /configure /db $seceditDbPath /cfg $outputInfPath /log $logFilePath /quiet\n     error_return \"加固失败，操作已回滚\"\n}\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n\n\n\n$key1 = \"System Access.ResetLockoutCount\"\n$value1 = $wgp_kvPairs[$key1]\nBackup-MultipleKeyValuesToInf -keysToBackup @($key1)\ntry {\n    if ([int]$value2 -ge 30 )\n    {\n        success_return \"配置项合规，无需加固\"\n    }\n    else\n    {\n        $wc = @\"\n[System Access]\nResetLockoutCount = 30\n\"@\n        $text = $wge_head + [Environment]::NewLine + $wc + [Environment]::NewLine + $wge_feet\n        $text | Set-Content -Path $winGbBaseLine\n        secedit /configure /db $seceditDbPath /cfg $winGbBaseLine /log $logFilePath /quiet\n        success_return \"加固完成，配置项已修改完成\"\n    }\n}\ncatch {\n    rollback\n}', '1', '1', '2024-09-09 10:14:59', '1', '2024-09-09 10:14:59', 0);
INSERT INTO `hrtool_reinforce_point` VALUES ('1832967187190980610', '1832237916759764993', '加固-检查是否已开启windows防火墙', 6, '1', '# 获取操作系统版本信息\n$osVersion = (Get-WmiObject -Class Win32_OperatingSystem).Version\n\nfunction error_return($message){\n	\"false|$message\"\n}\n\nfunction success_return($message){\n	 \"true|$message\"\n}\n# 检查 Windows 版本，分别处理不同情况\nif ($osVersion -like \"5.0*\") {\n    success_return \"无需加固，在 Windows 2000 系统中没有 Windows 防火墙，无需加固。\"\n}elseif ($osVersion -like \"5.1*\") {\n    error_return \"加固失败，在 Windows XP 或 XP SP1 系统中，请手动启用防火墙并设置例外\"\n}else {\n    $firewallResult = netsh advfirewall show currentprofile\n    $array = @()\n    $index = 0;\n    foreach ($line in $firewallResult)\n    {\n        if ($line -match \"(\\w+)\\s*(配置文件|Profile Settings)\")\n        {\n            $matchedText = $Matches[0]\n            $array += $matchedText\n        }\n        if ($line -match \"(状态|State)\\s+(\\w+)\")\n        {\n            $matchedText = $Matches[2]\n            $array[$index] = $array[$index] + \": \" + $matchedText\n            $index = $index + 1\n        }\n    }\n    # 初始化是否所有配置文件均为启用的标志\n    $allEnabled = $true\n    foreach ($entry in $array) {\n        # 如果检测到任何防火墙配置文件状态为 \"关闭\" (Off)，将标志设为 $false\n        if ($entry -match \": 关闭|: Off\") {\n            $allEnabled = $false\n        }\n    }\n\n    if ($allEnabled) {\n        success_return \"无需加固，所有防火墙配置文件均已启用。\"\n    } else {\n        error_return \"加固失败，请注意：某些防火墙配置文件未启用，启用防火墙为高风险操作未执行加固，请手动启用防火墙并按需配置例外。\"\n    }\n}\n\n', '1', '1', '2024-09-09 10:20:07', '1', '2024-09-09 10:20:07', 0);
