INSERT INTO `onl_cgform_enhance_js` VALUES ('0b326acbbc8e52c9c9ecdb19342fc3cf', 'show(){\n   console.log(\'form\',that)\n   //this.form.setFieldsValue({\"name\":\"name值\"})  \n  that.$nextTick(() => {\n           //age是对应表的字段名\n            that.form.setFieldsValue({\"age\":\"999\"})\n          });\n}\n\nonlChange(){\n   return {\n     \n     sex(){\n        let value = event.value\n        //alert(\'触发控件\',value)\n        \n         //性别改动，年龄归零\n        if(value!=null && value!=\"\"){   \n          let values = {\'age\':0}\n          that.triggleChangeValues(values)\n        }\n      }\n     \n    }\n }\n', 'form', NULL, '05a3a30dada7411c9109306aa4117068');
