INSERT INTO `std_checkitem` VALUES ('1529729416773640193', 'ubuntu-network-001', '检查网络连接是否存在与境外地址通信', 'A02A01A02', 'Linux', 'A03A02A03', '入侵防范', 0, NULL, '是否存在与境外地址通信', '使用netstat -anpt 对外部地址（foreign）地址进行截取，判断地址是否为境外地址，如是报警，并展示展示对应进程和文件路径                                      备注：部分服务器未安装net-tools的服务器无法使用该命令，碰到该问题报警', '低', 1, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:08:37', 'admin');
INSERT INTO `std_checkitem` VALUES ('1529729686098288641', 'ubuntu-network-002', '是否开启SSH端口', 'A02A01A02', 'Linux', 'A03A02A04', '安全审计', 0, NULL, '检查是否开启SSH端口', '使用netstat -anpt|grep ssh、netstat -anpt|grep 22检测系统是否开启ssh服务，如有', '低', 1, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:08:44', 'admin');
INSERT INTO `std_checkitem` VALUES ('1529730105545465857', 'ubuntu-network-003', '是否使用到50000以上端口', 'A02A01A02', 'Linux', 'A03A02A04', '安全审计', 0, NULL, '检测是否使用到50000以上端口', '使用netstat -anpt检测local address字段端口使用到50000以上端口，如是报警，并展示展示对应进程和文件路径', '低', 1, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:08:08', 'admin');
INSERT INTO `std_checkitem` VALUES ('1529730628365459457', 'ubuntu-account-001', '是否存在高权限账号', 'A02A01A02', 'Linux', 'A03A02A04', '安全审计', 0, NULL, '查看是否存在高权限账号', ' 使用awk -F: \'$3==0 {print $1}\' /etc/passwd  输出账号信息，判断是否为root，存在非root账号报警', NULL, NULL, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:08:03', 'admin');
INSERT INTO `std_checkitem` VALUES ('1529731047384817665', 'ubuntu-account-002', '启用账号是否存在空密码', 'A02A01A02', 'Linux', 'A03A02A04', '安全审计', 0, NULL, '检查启用账号是否存在空密码', '使用awk -F: ‘$3==0 {print $1}’ /etc/passwd筛选出空密码账号，输出已启用的空密码账号', NULL, NULL, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:07:56', 'admin');
INSERT INTO `std_checkitem` VALUES ('1529731499228798977', 'ubuntu-process-001', '可疑系统进程项', 'A02A01A02', 'Linux', 'A03A02A03', '入侵防范', 0, NULL, '检查是否存在可疑系统进程项', '使用  ps –ef  命令输出系统当前进程', NULL, NULL, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:07:51', 'admin');
