INSERT INTO `std_checkitem` VALUES ('1529732387787907073', 'ubuntu-startup-001', '可疑系统启动项', 'A02A01A02', 'Linux', 'A03A02A03', '入侵防范', 0, NULL, '检查可疑系统启动项', '使用systemctl list-unit-files', NULL, NULL, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:08:52', 'admin');
INSERT INTO `std_checkitem` VALUES ('1529733032339185666', 'ubuntu-account-003', '可疑系统账号', 'A02A01A02', 'Linux', 'A03A02A03', '入侵防范', 0, NULL, '检查可疑系统账号', '查看/etc/passwds输出未包含/sbin/nologin', NULL, NULL, NULL, NULL, 'A02A01A02', 0, '2022-05-26 00:00:00', 'admin', '2023-01-10 10:06:55', 'admin');
