INSERT INTO `std_checkitem` VALUES ('1612628856336433153', 'windows-resource-001', '系统CPU和内存使用情况检查', 'A02A01A05', 'Windows', 'A03A01A05', '资源控制', 0, NULL, '检查系统CPU、内存资源占用情况', 'WIN+R打开“运行”，输入命令resmon，打开资源监视器查看CPU和内存的占用率', '中', NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:54:15', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612629166366801921', 'windows-resource-002', '检查系统磁盘空间占用情况', 'A02A01A05', 'Windows', 'A03A01A05', '资源控制', 0, NULL, '检查系统磁盘空间占用情况', 'WIN+R打开“运行”，输入命令wmic，再输入命令logicaldisk查看每个磁盘的大小和占用剩余空间', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:55:29', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612629451285872642', 'windows-time-001', '系统时间检查', 'A02A01A05', 'Windows', 'A03A01A05', '资源控制', 0, NULL, '检查系统时间是否准确', '在CMD窗口中输入命令date查看当前日期，输入命令time查看当前时间', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:56:37', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612629627987705858', 'windows-account-001', '账号检查', 'A02A01A05', 'Windows', 'A03A01A04', '入侵防范', 0, NULL, '检查是否存在可疑账户', '1、WIN+R打开“运行”，输入命令cmd，再输入命令net user查看系统账号情况\n2、cmd窗口中输入命令net user 用户名', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:57:19', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612629750679486466', 'windows-process-001', '进程检查', 'A02A01A05', 'Windows', 'A03A01A04', '入侵防范', 0, NULL, '检查是否存在可疑进程', '1、cmd窗口中输入命令tasklist，查看进程的内存使用情况\n2、\n3、cmd窗口中输入命令netstat -ano，查看进程连接外部IP地址情况', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:57:48', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612629878458957825', 'windows-startup-001', '启动项检查', 'A02A01A05', 'Windows', 'A03A01A04', '入侵防范', 0, NULL, '检查是否存在可疑启动项', '1、WIN+R打开“运行”，输入命令regedit进入注册表，在\\HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run中查看启动项情况', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:58:19', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612630000664199169', 'windows-task-001', '计划任务检查', 'A02A01A05', 'Windows', 'A03A01A04', '入侵防范', 0, NULL, '检查是否存在可疑计划任务', 'cmd窗口中输入命令schtasks /query查看计划任务', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:58:48', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612630146454011906', 'windows-network-001', '端口检查', 'A02A01A05', 'Windows', 'A03A01A04', '入侵防范', 0, NULL, '检查是否存在可疑端口连接', '1、cmd窗口中输入命令netstat -ano，查看本地地址端口号和外部地址端口号为高危端口的访问情况\n2、cmd窗口中输入命令netstat -ano，查看本地地址端口号为远程管理端口的访问情况\n3、cmd窗口中输入命令netstat -ano，查看本地地址端口号为数据库端口的访问情况\n4、cmd窗口中输入命令netstat -ano，查看本地地址高端口号使用情况', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 09:59:23', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612630324766457858', 'windows-evenlog-001', '日志检查', 'A02A01A05', 'Windows', 'A03A01A02', '安全审计', 0, NULL, '检查是否存在异常日志行为', 'cmd窗口中输入命令eventvwr，进入事件查看器-Windows日志-安全，查看是否存在异常日志', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 10:00:05', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612630499069149185', 'windows-firewalld-001', '防火墙启用状态检查', 'A02A01A05', 'Windows', 'A03A01A01', '访问控制', 0, NULL, '检查防火墙是否启用', 'cmd窗口中输入命令netsh advfirewall show allprofiles查看防火墙启用状态', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 10:00:47', 'admin', NULL, NULL);
INSERT INTO `std_checkitem` VALUES ('1612630681802391554', 'windows-avast-001', '杀毒软件检查', 'A02A01A05', 'Windows', 'A03A01A04', '入侵防范', 0, NULL, '检查是否安装统一管理杀毒软件', '人工检查手动填写', NULL, NULL, NULL, NULL, 'A02A01A05', 0, '2023-01-10 10:01:30', 'admin', NULL, NULL);
